      </div>
      
      {/* Caret / Cursor Highlight for active field */}
      {isFocused && (
        <motion.div 
          layoutId="input-glow"
          className="absolute inset-0 bg-emerald-500/10 blur-2xl -z-10 rounded-3xl"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
