import React, { useEffect, useState } from 'react';
import { FilsIcon } from './CurrencyIcon';
import { playCoinSfx } from '../utils/audio';

const CoinAnimation = ({ trigger, isDaily, amount = 0 }) => {
  const [coins, setCoins] = useState([]);

  useEffect(() => {
    if (trigger) {
      // Dynamic Scaling: Number of coins based on reward amount
      // Standard win (~100 fils) = 20-25 coins
      // Daily win (~1000 fils) = 50-60 coins
      // Hard/Secret win (2500+ fils) = 80-100 coins
      let length = Math.min(100, Math.max(15, Math.floor((amount || 100) / 10)));
      if (isDaily) length = Math.max(length, 45); // Daily minimum boost

      // Multi-Play Sound Burst Logic (Scaled to intensity)
      const soundCount = Math.min(12, Math.max(3, Math.floor(length / 7)));
      for (let i = 0; i < soundCount; i++) {
        setTimeout(() => {
          playCoinSfx();
        }, i * (isDaily ? 50 : 80));
      }

      const newCoins = Array.from({ length }).map((_, i) => ({
        id: Date.now() + i,
        delay: i * (isDaily ? 0.04 : 0.06),
        x: Math.random() * 160 - 80, 
        y: Math.random() * 160 - 80,
      }));
      setCoins(newCoins);

      const timer = setTimeout(() => {
        setCoins([]);
      }, 3500); // Clear after animation
      return () => clearTimeout(timer);
    }
  }, [trigger, isDaily]);

  if (coins.length === 0) return null;

  const targetX = window.innerWidth * 0.42; 
  const targetY = -window.innerHeight * 0.46;

  return (
    <div className="fixed inset-0 z-110 flex items-center justify-center pointer-events-none">
      {coins.map((coin) => (
        <div
          key={coin.id}
          className="coin-icon"
          style={{
            '--target-x': `${targetX}px`,
            '--target-y': `${targetY}px`,
            animationDelay: `${coin.delay}s`,
            left: `calc(50% + ${coin.x}px)`,
            top: `calc(50% + ${coin.y}px)`
          }}
        >
          <div className="w-12 h-12 flex items-center justify-center filter drop-shadow-[0_4px_8px_rgba(0,0,0,0.5)]">
            <FilsIcon size={44} className="hover:scale-110 transition-transform" />
          </div>
        </div>
      ))}
    </div>
  );
};

export default CoinAnimation;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FilsIcon, DerhemIcon, ZerIcon } from './CurrencyIcon';
import { toKuDigits } from '../utils/formatters';
import { playCoinSfx } from '../utils/audio';

/**
 * CurrencyDecrementEffect
 * A premium feedback component that displays a floating "-X [Icon]" animation 
 * whenever the provided value decreases.
 */
const CurrencyDecrementEffect = ({ value, currency, children, className = "" }) => {
  const [changes, setChanges] = useState([]);
  const prevValue = useRef(value);

  useEffect(() => {
    // Detect decrease
    const numericValue = Number(value) || 0;
    const previousNumericValue = Number(prevValue.current) || 0;

    if (numericValue < previousNumericValue) {
      const diff = previousNumericValue - numericValue;
      const id = Date.now() + Math.random();

      // Play sound effect
      playCoinSfx();

      setChanges(prev => [...prev.slice(-2), { id, diff }]);

      // Auto-cleanup
      const timer = setTimeout(() => {
        setChanges(prev => prev.filter(c => c.id !== id));
      }, 2000);
      return () => clearTimeout(timer);
    }
    prevValue.current = value;
  }, [value]);

  const IconComponent = () => {
    const props = { className: "w-5 h-5", size: 20 };
    switch (currency) {
      case 'derhem': return <DerhemIcon {...props} />;
      case 'zer': return <ZerIcon {...props} />;
      case 'fils':
      default: return <FilsIcon {...props} />;
    }
  };

  return (
    <div className={`relative flex items-center justify-center ${className}`} style={{ isolation: 'isolate' }}>
      {children}

      {/* Animation Layer */}
      <div className="absolute inset-0 pointer-events-none flex items-center justify-center" style={{ zIndex: 9999 }}>
        <AnimatePresence mode="popLayout">
          {changes.map(change => (
            <motion.div
              key={change.id}
              initial={{ opacity: 0, y: 10, scale: 0.5, filter: 'blur(4px)' }}
              animate={{ 
                opacity: [0, 1, 1, 0], 
                y: -60, 
                scale: [0.5, 1.2, 1, 0.8],
                filter: 'blur(0px)'
              }}
              exit={{ opacity: 0, scale: 0.5 }}
              transition={{ 
                duration: 1.8, 
                times: [0, 0.2, 0.8, 1],
                ease: "easeOut" 
              }}
              className="absolute flex items-center gap-2 bg-linear-to-r from-red-500/20 to-transparent px-3 py-1 rounded-full border border-red-500/30 backdrop-blur-sm"
            >
              <span className="text-[#ff4d4d] font-black text-2xl drop-shadow-[0_0_10px_rgba(255,0,0,0.6)]">
                -{toKuDigits(change.diff)}
              </span>
              <div className="flex items-center justify-center drop-shadow-[0_0_5px_rgba(255,0,0,0.4)] brightness-125">
                 <IconComponent />
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default CurrencyDecrementEffect;

import React, { useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { triggerHaptic } from '../utils/haptics';
import { FilsIcon } from './CurrencyIcon';
import { useState } from 'react';

const AnimatedNumber = ({ value, prefix = "" }) => {
  const [displayValue, setDisplayValue] = useState(0);

  useEffect(() => {
    let start = 0;
    const end = parseInt(value) || 0;
    const duration = 1500; // 1.5s
    const startTime = performance.now();

    const update = (now) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // Ease out expo
      const easeProgress = progress === 1 ? 1 : 1 - Math.pow(2, -10 * progress);

      setDisplayValue(Math.floor(start + (end - start) * easeProgress));

      if (progress < 1) {
        requestAnimationFrame(update);
      }
    };

    requestAnimationFrame(update);
  }, [value]);

  return <span>{prefix}{displayValue}</span>;
};

const DefeatOverlay = ({ 
  isVisible, 
  solvedWord, 
  onRetry, 
  onHome,
  breakdown,
  gameMode = 'classic'
