import React from 'react';
import { motion } from 'framer-motion';
import { DerhemIcon } from './CurrencyIcon';
import { triggerHaptic } from '../utils/haptics';

export default function LobbyView({ 
  onStartClassic, 
  onStartMamak,
  onStartHardWords, 
  onStartSecretWord, 
  onStartWordFever, 
  onStartMultiplayer, // Handle matchmaking
  onSocialClick, 
  dailyStreak,
  onViewChange,
  notificationCount = 0,
  winsTowardsSecret = 0
}) {
  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    show: { 
      opacity: 1, 
      y: 0, 
      transition: { 
        type: 'spring', 
        stiffness: 300, 
        damping: 24 
      } 
    }
  };

  const bentoMotionProps = {
    whileHover: { scale: 1.05 },
    whileTap: { scale: 0.95 },
    transition: { type: "spring", stiffness: 400, damping: 17 }
  };

  const isSecretUnlocked = winsTowardsSecret >= 3;

  return (
    <motion.div 
      variants={containerVariants}
      initial="hidden"
      animate="show"
      className="flex-1 w-full max-w-full px-4 pt-4 pb-4 overflow-x-hidden bg-[#020617] relative min-h-screen"
    >
      {/* WORDLE BACKGROUND (FLOATING LETTERS) - MATCHING RANKING STYLE */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden z-0 opacity-50">
        {[...Array(18)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute text-white font-black text-xl select-none font-rabar pointer-events-none"
            style={{ 
              left: Math.random() * 95 + '%', 
              top: Math.random() * 95 + '%',
            }}
            animate={{ 
              y: [0, -30, 30, 0], 
              x: [0, 40, -40, 0],
              rotate: [0, 15, -15, 0],
              opacity: [0.2, 0.4, 0.2],
              scale: [0.95, 1.05, 0.95]
            }}
            transition={{ 
              duration: 20 + Math.random() * 20, 
              repeat: Infinity, 
              ease: "easeInOut" 
            }}
          >
            {['ئا', 'ب', 'پ', 'ت', 'ج', 'د', 'ڕ', 'ز', 'ڤ', 'ڵ', 'ۆ', 'ێ'][i % 12]}
          </motion.div>
        ))}
      </div>

      <div className="relative z-10">
        <div className="grid grid-cols-2 gap-4">

          {/* ONLINE MULTIPLAYER (NEW) */}
          <motion.button 
            variants={itemVariants}
            onClick={() => { triggerHaptic(15); onStartMultiplayer(); }}
            {...bentoMotionProps}
            className="col-span-2 relative h-28 rounded-[32px] overflow-hidden bg-gradient-to-r from-emerald-500 to-teal-600 shadow-xl group border-none"
          >
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10 mix-blend-overlay" />
            <div className="relative z-10 flex items-center justify-between px-8 h-full">
              <div className="flex flex-col items-start">
                <h3 className="text-2xl font-black font-heading text-white">ھەڤڕکی</h3>
                <span className="text-[10px] font-medium font-rabar uppercase tracking-[0.2em] text-emerald-100/70 leading-none">دەستەودەست (ONLINE)</span>
              </div>
              <div className="w-14 h-14 rounded-2xl bg-white/20 flex items-center justify-center border border-white/30 shadow-[0_0_20px_rgba(255,255,255,0.2)] group-hover:scale-110 group-hover:rotate-12 transition-all duration-300">
                <span className="material-symbols-outlined text-4xl text-white">groups</span>
              </div>
            </div>

            {/* Animated Pulse Ring */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full border-4 border-white/10 rounded-[32px] animate-pulse pointer-events-none" />
          </motion.button>

          {/* CLASSIC MODE */}
          <motion.button 
            variants={itemVariants}
            onClick={() => { triggerHaptic(10); onStartClassic(); }}
            {...bentoMotionProps}
            className="col-span-2 relative h-24 rounded-[32px] overflow-hidden bg-[#ffcc00] shadow-xl group border-none"
          >
            <div className="relative z-10 flex items-center justify-between px-8 h-full">
              <div className="flex flex-col items-start">
                <h3 className="text-xl font-black font-heading text-amber-950">پەیڤچن</h3>
                <span className="text-[9px] font-medium font-rabar uppercase tracking-[0.2em] text-amber-900/80 leading-none">کلاسیک</span>
              </div>
              <div className="w-12 h-12 rounded-xl bg-white/20 flex items-center justify-center border border-white/30 shadow-sm group-hover:scale-110 transition-transform">
                <span className="material-symbols-outlined text-3xl text-amber-950">videogame_asset</span>
              </div>
            </div>
          </motion.button>

          {/* MAMAK MODE */}
          <motion.button 
            variants={itemVariants}
            onClick={() => { triggerHaptic(10); onStartMamak(); }}
            {...bentoMotionProps}
            className="col-span-2 relative h-24 rounded-[32px] overflow-hidden bg-[#22c55e] shadow-xl group border-none"
          >
            <div className="relative z-10 flex items-center justify-between px-8 h-full">
              <div className="flex flex-col items-start">
                <h3 className="text-xl font-black font-heading text-white">مامک</h3>
                <span className="text-[9px] font-medium font-rabar uppercase tracking-[0.2em] text-white/50 leading-none">پەیدا بکە</span>
              </div>
              <div className="w-12 h-12 rounded-xl bg-white/20 flex items-center justify-center border border-white/30 shadow-sm group-hover:scale-110 transition-transform">
                <span className="material-symbols-outlined text-3xl text-white">emoji_objects</span>
              </div>
            </div>
          </motion.button>

          {/* HARD MODE */}
          <motion.button 
            variants={itemVariants}
            onClick={() => { triggerHaptic(10); onStartHardWords(); }}
            {...bentoMotionProps}
            className="col-span-1 relative h-36 rounded-[32px] overflow-hidden bg-[#ef4444] shadow-xl group border-none"
          >
            <div className="relative z-10 flex flex-col items-center justify-center h-full gap-2 text-center">
              <div className="w-11 h-11 rounded-xl bg-white/20 flex items-center justify-center border border-white/30 group-hover:rotate-12 transition-transform shadow-sm">
                <span className="material-symbols-outlined text-2xl text-white">workspace_premium</span>
              </div>
              <div className="flex flex-col items-center">
                <h3 className="text-lg font-black font-heading text-white">پەیڤێن دژوار</h3>
                <span className="text-[9px] font-medium font-rabar uppercase tracking-wider text-white/50 mt-1 leading-none">بۆ شارەزایان</span>
                <div className="flex items-center gap-1.5 bg-black/20 px-2 py-0.5 rounded-full border border-white/20 mt-1">
                  <DerhemIcon className="w-2.5 h-2.5 saturate-[0] brightness-[100]" />
                  <span className="text-[10px] font-black text-white font-ui">{dailyStreak}</span>
                </div>
              </div>
            </div>
          </motion.button>

          {/* WORD FEVER MODE */}
          <motion.button 
            variants={itemVariants}
            onClick={() => { triggerHaptic(10); onStartWordFever(); }}
            {...bentoMotionProps}
            className="col-span-1 relative h-36 rounded-[32px] overflow-hidden bg-[#0ea5e9] shadow-xl group border-none"
          >
            <div className="relative z-10 flex flex-col items-center justify-center h-full gap-2 text-center">
              <div className="w-11 h-11 rounded-xl bg-white/20 flex items-center justify-center border border-white/30 group-hover:scale-110 transition-transform shadow-sm">
                <span className="material-symbols-outlined text-2xl text-white">electric_bolt</span>
              </div>
              <div className="flex flex-col items-center">
                <h3 className="text-lg font-black font-heading text-white">تایا پەیڤان</h3>
                <span className="text-[9px] font-medium font-rabar uppercase tracking-widest text-white/50 mt-1 leading-none">بەرھەڤ بە</span>
              </div>
            </div>
          </motion.button>

          {/* SECRET MODE - Progressive Unlock */}
          <motion.button 
            variants={itemVariants}
            disabled={!isSecretUnlocked}
            onClick={() => { triggerHaptic(10); if (isSecretUnlocked) onStartSecretWord(); }}
            {...(isSecretUnlocked ? bentoMotionProps : {})}
            className={`col-span-2 relative h-24 rounded-[32px] overflow-hidden transition-all duration-500 shadow-xl border-none ${
              isSecretUnlocked 
                ? 'bg-gradient-to-br from-[#2e1065] to-[#4c1d95] border-2 border-yellow-400/50 shadow-[0_0_40px_rgba(0,0,0,0.8)]' 
                : 'bg-white/5 border border-white/10 backdrop-blur-md opacity-80'
            }`}
          >
            <div className="relative z-10 flex items-center justify-between px-8 h-full">
              <div className="flex flex-col items-start text-right">
                <h3 className={`text-xl font-black font-heading ${isSecretUnlocked ? 'text-white' : 'text-white/40'}`}>پەیڤا نھێنی</h3>

                {/* Unlock Progress Dots */}
                <div className="flex items-center gap-1.5 mt-1 bg-black/20 px-2.5 py-1 rounded-full border border-white/10">
                  {[1, 2, 3].map((dot) => (
                    <div 
                      key={dot}
                      className={`w-1.5 h-1.5 rounded-full transition-all duration-500 ${
                        dot <= winsTowardsSecret 
                          ? 'bg-yellow-400 shadow-[0_0_8px_rgba(250,204,21,0.6)]' 
                          : 'bg-white/10'
                      }`}
                    />
                  ))}
                  {!isSecretUnlocked && (
                    <span className="text-[8px] font-bold text-white/30 mr-2 uppercase tracking-widest">
                      {winsTowardsSecret}/٣
                    </span>
                  )}
                </div>
              </div>

              <div className={`w-11 h-11 rounded-xl flex items-center justify-center border transition-all duration-500 ${
                isSecretUnlocked 
                  ? 'bg-yellow-400/20 border-yellow-400 shadow-[0_0_15px_rgba(250,204,21,0.3)] animate-pulse' 
                  : 'bg-white/5 border-white/10'
              }`}>
                <span className={`material-symbols-outlined text-2xl transition-all ${
                  isSecretUnlocked ? 'text-yellow-400 scale-110' : 'text-white/20'
                }`}>
                  {isSecretUnlocked ? 'vpn_key' : 'lock'}
                </span>
              </div>
            </div>

            {/* Golden Key Glow Background for Unlocked state */}
            {isSecretUnlocked && (
              <div className="absolute inset-0 bg-gradient-to-r from-yellow-400/5 to-transparent pointer-events-none" />
            )}
          </motion.button>
        </div>
      </div>
    </motion.div>
  );
}

import React, { useEffect, useCallback, useMemo, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Grid from './Grid';
import Keyboard from './Keyboard';
import { useMultiplayer } from '../context/MultiplayerContext';
import { useGame } from '../context/GameContext';
import useGameLogic from '../hooks/useGameLogic';
import Avatar from './Avatar';
import KurdishSunLoader from './KurdishSunLoader';
import { triggerHaptic } from '../utils/haptics';

export default function MultiplayerGameView({ opponent: propOpponent }) {
  const { 
    activeMatch, 
    opponent: contextOpponent, 
    submitGuess, 
    broadcastGuess,
    opponentGuesses, 
    scores, 
    currentRound,
    isRoundWinner,
    winnerNickname,
    roundMessage,
    multiplayerState,
    setMultiplayerState,
    fetchOpponentProfile,
    cancelMatch
  } = useMultiplayer();

  // Prioritize Prop over Context to force re-renders from App.jsx
  const opponent = propOpponent || contextOpponent;
  
  const [isConfirmingExit, setIsConfirmingExit] = useState(false);
  
  const { user, userNickname, userAvatar, playPopSound, playVictorySound, playStartSound } = useGame();
  
  // 1. TOP-LEVEL DERIVED DATA (DECLARE BEFORE ANY RETURNS)
  const isPlayer1 = useMemo(() => activeMatch?.player1_id === user?.id, [activeMatch, user]);
  const targetWord = useMemo(() => {
    if (!activeMatch?.words) return '';
    return (activeMatch.words[currentRound]) || (activeMatch.words[0]) || '';
  }, [activeMatch, currentRound]);

  // CORE ENGINE
  const onGuessSubmitted = useCallback(async (colors, isWin) => {
    if (isWin) {
        await submitGuess(colors, true);
        playVictorySound();
    } else {
        broadcastGuess(colors, false);
        playPopSound(true);
    }
  }, [submitGuess, broadcastGuess, playVictorySound, playPopSound]);

  const {
    guesses,
    currentGuess,
    usedKeys,
    onKey,
    onDelete,
    onEnter,
    getLetterStatus,
    resetLocalBoard
  } = useGameLogic({
    targetWord,
    maxRows: 3,
    gameMode: 'multiplayer',
    onGuessSubmitted
  });

  // 3. IDENTITY HEALING: Ensure opponent is fetched if missing
  useEffect(() => {
    if (activeMatch && !opponent) {
      const oppId = isPlayer1 ? activeMatch.player2_id : activeMatch.player1_id;
      if (oppId) {
        fetchOpponentProfile(oppId);
      }
    }
  }, [activeMatch, opponent, isPlayer1, fetchOpponentProfile]);

  // Handle board reset when round changes or word loads
  useEffect(() => {
    if (targetWord) {
      resetLocalBoard(targetWord);
    }
  }, [currentRound, targetWord, resetLocalBoard, playStartSound]);

  // --- GUARDS & EARLY RETURNS (Declare AFTER all hooks) ---
  if (!activeMatch) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <KurdishSunLoader />
        <p className="mt-8 text-white/40 font-noto-sans-arabic animate-pulse">بەرھەڤکرنا پەیڤان...</p>
      </div>
    );
  }



  if (multiplayerState === 'waiting') {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#020617] text-white">
        <KurdishSunLoader />
        <p className="mt-8 text-emerald-100/40 font-rabar animate-pulse">بەرھەڤکرنا یاریێ...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-[100dvh] bg-[#020617] overflow-hidden">
      <style>
        {`
          .battle-grid-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 8px 0;
            flex: 1;
            min-height: 0;
          }
        `}
      </style>
      
      {/* 1. SCOREBOARD (Dedicated Header) */}
      <div className="px-6 py-4 bg-white/5 border-b border-white/10 flex items-center justify-between">
        {/* RIGHT (First child in RTL): OPPONENT */}
        <div className="flex items-center gap-3 text-right">
          <motion.div
            animate={{ opacity: (activeMatch?.opp_avatar_url || opponent?.avatar_url) ? 1 : 0.5 }}
            transition={{ duration: 0.5 }}
          >
            <Avatar src={activeMatch?.opp_avatar_url || opponent?.avatar_url} size="sm" />
          </motion.div>
          <div className="flex flex-col text-right">
            <span className="text-sm font-black text-amber-400 truncate max-w-[100px]">
              {(activeMatch?.opp_nickname || opponent?.nickname || 'چاڤەڕێ...').toUpperCase()}
            </span>
            <span className="text-xl font-black text-white">{isPlayer1 ? scores.p2 : scores.p1}</span>
          </div>
        </div>

        {/* CENTER: ROUND & VS */}
        <div className="flex flex-col items-center relative">
            <div className="text-[10px] bg-emerald-500/20 text-emerald-400 px-3 py-1 rounded-full font-black mb-1">BATTLE</div>
            <div className="text-xs font-black text-white/30 truncate">گەڕ {currentRound}/3</div>
        </div>

        {/* LEFT (Last child in RTL): YOU */}
        <div className="flex items-center gap-4 text-left">
          <div className="flex flex-col text-left">
            <span className="text-sm font-black text-emerald-400 truncate max-w-[100px]">{(userNickname || 'یاریزان').toUpperCase()}</span>
            <span className="text-xl font-black text-white">{isPlayer1 ? scores.p1 : scores.p2}</span>
          </div>
          <Avatar src={userAvatar} size="sm" />
        </div>
      </div>


      {/* 2. SYMMETRIC BATTLEFIELD */}
