   fils,
   derhem,
   zer,
   playerStats,
   userRank,
   onViewChange,
   maxXP,
   dailyStreak
}) {
   const [activeTab, setActiveTab] = useState('profile');
   const [isFlagBoxOpen, setIsFlagBoxOpen] = useState(false);
   const [isAvatarBoxOpen, setIsAvatarBoxOpen] = useState(false);
   const [isUploading, setIsUploading] = useState(false);
   const [dropdownCoords, setDropdownCoords] = useState({ top: 0, left: 0, width: 0 });
   const fileInputRef = useRef(null);
   const flagDropdownRef = useRef(null);
   const flagButtonRef = useRef(null);
   const [draftNickname, setDraftNickname] = useState(userNickname);
   const [draftAvatar, setDraftAvatar] = useState(userAvatar);
   const [draftCountryCode, setDraftCountryCode] = useState(countryCode);
   const [draftIsInKurdistan, setDraftIsInKurdistan] = useState(isInKurdistan);
   const [saveSuccess, setSaveSuccess] = useState(false);
   const [dbLoading, setDbLoading] = useState(false);
   const [isNicknameLocked, setIsNicknameLocked] = useState(true);
   const [pendingFile, setPendingFile] = useState(null);
   const [localPreviewUrl, setLocalPreviewUrl] = useState(null);
   const nicknameInputRef = useRef(null);

   useEffect(() => {
      setDraftNickname(userNickname);
      setDraftAvatar(userAvatar);
      setDraftCountryCode(countryCode);
      setDraftIsInKurdistan(isInKurdistan);
   }, [userNickname, userAvatar, countryCode, isInKurdistan]);

   useEffect(() => {
      if (isFlagBoxOpen && flagButtonRef.current) {
         const rect = flagButtonRef.current.getBoundingClientRect();
         setDropdownCoords({
            top: rect.bottom + window.scrollY,
            left: rect.left + window.scrollX,
            width: rect.width
         });
      }
   }, [isFlagBoxOpen]);

   useEffect(() => {
      function handleClickOutside(event) {
         if (flagDropdownRef.current && !flagDropdownRef.current.contains(event.target) &&
            flagButtonRef.current && !flagButtonRef.current.contains(event.target)) {
            setIsFlagBoxOpen(false);
         }
      }
      if (isFlagBoxOpen) {
         document.addEventListener('mousedown', handleClickOutside);
         window.addEventListener('scroll', () => setIsFlagBoxOpen(false), { once: true });
         window.addEventListener('resize', () => setIsFlagBoxOpen(false), { once: true });
      }
      return () => {
         document.removeEventListener('mousedown', handleClickOutside);
      };
   }, [isFlagBoxOpen]);

   if (!user || user === null) {
      return <div className="flex flex-col items-center justify-center h-40"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div></div>;
   }

   const getLevelData = (xp) => {
      const baseXP = 500;
      const factor = 1.1;
      if (xp <= 0) return { level: 1, progressPercent: 0 };
      const lvl = Math.floor(Math.log(xp * (factor - 1) / baseXP + 1) / Math.log(factor)) + 1;
      const currentLevelBase = baseXP * (Math.pow(factor, lvl - 1) - 1) / (factor - 1);
      const nextLevelBase = baseXP * (Math.pow(factor, lvl) - 1) / (factor - 1);
      const width = nextLevelBase - currentLevelBase;
      const progress = xp - currentLevelBase;
      return { level: lvl, progressPercent: Math.min(100, (progress / width) * 100) };
   };

   const levelInfo = getLevelData(Number(currentXP) || 0);
   const safeLevel = levelInfo.level;
   const progressPercent = Math.round(levelInfo.progressPercent);
   const effectiveProgress = levelInfo.progressPercent / 100;

   const getLevelTier = (lvl) => {
      if (lvl < 10) return { stop1: '#cd7f32', stop2: '#f97316', shadow: 'rgba(249, 115, 22, 0.4)' };
      if (lvl < 25) return { stop1: '#cbd5e1', stop2: '#94a3b8', shadow: 'rgba(148, 163, 184, 0.4)' };
      if (lvl < 45) return { stop1: '#fbbf24', stop2: '#d97706', shadow: 'rgba(245, 158, 11, 0.4)' };
      if (lvl < 70) return { stop1: '#22d3ee', stop2: '#0891b2', shadow: 'rgba(6, 182, 212, 0.4)' };
      if (lvl < 90) return { stop1: '#a855f7', stop2: '#7c3aed', shadow: 'rgba(139, 92, 246, 0.4)' };
      return { stop1: '#ef4444', stop2: '#b91c1c', shadow: 'rgba(239, 68, 68, 0.4)' };
   };

   const tier = getLevelTier(level);

   const handleImageUpload = (e) => {
      const file = e.target.files[0];
      if (!file) return;
      setPendingFile(file);
      const preview = URL.createObjectURL(file);
      setLocalPreviewUrl(preview);
      setDraftAvatar(preview);
      setIsAvatarBoxOpen(false);
      triggerHaptic(10);
   };

   const handleInvite = () => {
      const shareLink = `${window.location.origin}/play?invite=${user?.id || 'guest'}`;
      navigator.clipboard.writeText(shareLink);
      alert('لینک ھاتە کۆپیکرن! بۆ ھەڤالێن خۆ بفرێژە.');
   };

   const handleSave = async () => {
      try {
         setIsUploading(true);
         triggerHaptic([20, 10, 20]);
         let finalAvatar = draftAvatar;

         if (pendingFile) {
            try {
               const fileExt = pendingFile.name.split('.').pop();
               const fileName = `${user?.id || 'guest'}-${Date.now()}.${fileExt}`;

               const { data, error: uploadError } = await supabase.storage
                  .from('avatars')
                  .upload(fileName, pendingFile);

               if (!uploadError) {
                  const { data: { publicUrl } } = supabase.storage
                     .from('avatars')
                     .getPublicUrl(fileName);
                  finalAvatar = publicUrl;
               } else {
                  console.error("Upload error details:", uploadError);
               }
            } catch (upErr) {
               console.error("Upload process crashed:", upErr);
            }
         }

         await onProfileSave({ nickname: draftNickname, avatar_url: finalAvatar, countryCode: draftCountryCode, isInKurdistan: draftIsInKurdistan });
         setSaveSuccess(true);
         setIsNicknameLocked(true);
         setPendingFile(null);
         if (localPreviewUrl) URL.revokeObjectURL(localPreviewUrl);
         setLocalPreviewUrl(null);
         setTimeout(() => setSaveSuccess(false), 2000);
      } catch (err) { alert(`خەلەتی: ${err.message}`); } finally { setIsUploading(false); }
   };

   const selectedCountryName = draftIsInKurdistan ? 'کوردستان' : (COUNTRIES.find(c => c.code === draftCountryCode)?.name || 'جیھان');

   return (
      <div className="w-screen max-w-full mx-auto h-full flex flex-col pt-0 pb-0 overflow-x-hidden relative z-10">

         <div className="px-5 mb-4 text-center flex flex-col items-center">
            <div className="relative w-full aspect-square max-w-[340px] rounded-[40px] overflow-hidden border border-white/10 shadow-[0_25px_50px_-12px_rgba(0,0,0,0.8)] bg-slate-950 group">

               <div className="absolute inset-0 bg-gradient-to-b from-[#1a1c2c] via-[#0a0b14] to-black opacity-100"></div>

               <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-black/20 z-50 overflow-hidden">
                  <motion.div
                     key="liquid-xp-bar"
                     initial={{ height: 0 }}
                     animate={{ height: `${progressPercent}%` }}
                     transition={{ duration: 2, ease: "circOut" }}
                     className="absolute bottom-0 left-0 w-full rounded-t-full shadow-[0_0_10px_rgba(255,255,255,0.4)]"
                     style={{
                        background: `linear-gradient(to top, ${tier.stop2}, ${tier.stop1}, #fff)`
                     }}
                  >
                     <div className="absolute inset-0 overflow-hidden pointer-events-none">
                        {[...Array(2)].map((_, i) => (
                           <motion.div
                              key={i}
                              className="absolute bottom-0 w-1 h-1 bg-white/40 rounded-full blur-[1px]"
                              animate={{ y: [-10, -100], opacity: [0, 1, 0] }}
                              transition={{ duration: 2 + Math.random(), repeat: Infinity, delay: i * 0.5 }}
                           />
                        ))}
                     </div>
                  </motion.div>
               </div>

               <svg
                  className="absolute inset-0 w-full h-full pointer-events-none z-50 transform -rotate-90"
                  viewBox="0 0 340 340"
                  preserveAspectRatio="none"
                  fill="none"
                  xmlns="http://www.w3.org/2000/svg"
               >
                  <defs>
                     <linearGradient id="barGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                        <stop offset="0%" stopColor={tier.stop1} />
                        <stop offset="100%" stopColor={tier.stop2} />
                     </linearGradient>
                  </defs>
                  <rect
                     x="3" y="3"
                     width="334" height="334"
                     rx="38"
                     stroke="white"
                     strokeWidth="4"
                     strokeOpacity="0.03"
                  />
                  <motion.rect
                     x="3" y="3"
                     width="334" height="334"
                     rx="38"
                     stroke={tier.stop1}
                     strokeWidth="10"
                     strokeLinecap="round"
                     initial={{ pathLength: 0 }}
                     animate={{ pathLength: effectiveProgress }}
                     transition={{ duration: 2, ease: "circOut" }}
                     className="opacity-20 blur-[8px]"
                  />
                  <motion.rect
                     x="3" y="3"
                     width="334" height="334"
                     rx="38"
                     stroke="url(#barGradient)"
                     strokeWidth="6"
                     strokeLinecap="round"
                     initial={{ pathLength: 0 }}
                     animate={{ pathLength: effectiveProgress }}
                     transition={{ duration: 2, ease: "circOut" }}
                  />
               </svg>

               <div className="absolute inset-0 opacity-15 bg-[url('https://www.transparenttextures.com/patterns/hexellence.png')] mix-blend-overlay"></div>

               <div className="absolute top-0 left-0 right-0 h-16 z-50 px-6 flex justify-between items-center" dir="ltr">
                  <div className="w-10 h-10 flex items-center justify-center">
                     <AnimatePresence>
                        {(draftAvatar !== userAvatar || pendingFile || draftNickname !== userNickname || draftCountryCode !== countryCode) && !saveSuccess && (
                           <motion.button
                              initial={{ scale: 0, rotate: -90 }}
                              animate={{ scale: 1, rotate: 0 }}
                              exit={{ scale: 0, rotate: 90 }}
                              onClick={(e) => { e.stopPropagation(); handleSave(); }}
                              disabled={isUploading}
                              className="w-12 h-12 bg-primary text-slate-950 rounded-2xl shadow-[0_0_30px_rgba(var(--primary-rgb),0.6)] flex items-center justify-center border-2 border-white/40 hover:scale-110 active:scale-95 transition-all"
                           >
                              {isUploading ? (
                                 <div className="w-5 h-5 border-2 border-slate-950/30 border-t-slate-950 rounded-full animate-spin"></div>
                              ) : (
                                 <span className="material-symbols-outlined text-2xl font-black">check_circle</span>
                              )}
                           </motion.button>
                        )}
                     </AnimatePresence>
                  </div>

                  <div className="relative flex flex-col items-center pt-5">
                     <div className="flex flex-col items-center relative group/medal">
                        <div className="relative w-14 h-15 flex items-center justify-center">
                           <svg className="absolute inset-0 w-full h-full drop-shadow-2xl" viewBox="0 0 100 115" fill="none" xmlns="http://www.w3.org/2000/svg">
                              <path d="M50 0L95 20V55C95 80 50 115 50 115C50 115 5 80 5 55V20L50 0Z" fill="url(#medalGradient)" stroke="white" strokeWidth="4" strokeOpacity="0.2" />
                              <defs>
                                 <linearGradient id="medalGradient" x1="50" y1="0" x2="50" y2="115" gradientUnits="userSpaceOnUse">
                                    <stop stopColor="#FFD700" />
                                    <stop offset="1" stopColor="#B8860B" />
                                 </linearGradient>
                              </defs>
                           </svg>
                           <div className="relative z-10 flex flex-col items-center justify-center -mt-2">
                              <span className="text-[9px] font-black text-slate-950/40 uppercase leading-none mb-0.5">ئاست</span>
                              <span className="text-2xl font-black text-slate-950 leading-none drop-shadow-sm">{toKuDigits(safeLevel)}</span>
                           </div>
                        </div>
                     </div>
                  </div>
               </div>

               <div className="absolute top-4 left-0 right-0 flex flex-col items-center z-20">
                  <div className="relative w-40 h-40 flex items-center justify-center">
                     <div
                        className="relative z-10 cursor-pointer hover:scale-105 active:scale-95 transition-all duration-300"
                        onClick={() => { triggerHaptic(10); fileInputRef.current?.click(); }}
                     >
                        <div className="relative">
                           <Avatar src={draftAvatar} size="xl" className="w-32 h-32 rounded-full border-4 border-slate-950 shadow-2xl z-20" updatedAt={user?.updated_at} />
                           <div className="absolute bottom-1 right-2 w-9 h-9 bg-white text-slate-950 rounded-full shadow-lg border-2 border-slate-950 flex items-center justify-center z-30">
                              <span className="material-symbols-outlined text-[18px] font-black">photo_camera</span>
                           </div>
                        </div>
                     </div>
                  </div>
               </div>

               <div className="absolute bottom-4 left-4 right-4 z-40 text-right" dir="rtl">
                  <div className="bg-slate-900/40 backdrop-blur-2xl rounded-[28px] border border-white/5 p-4 shadow-2xl relative overflow-hidden">
                     <div className="absolute top-4 left-4 flex items-center gap-1 opacity-80 hover:opacity-100 transition-opacity">
                        <span className="text-orange-500 font-black text-sm">{toKuDigits(dailyStreak || 0)}</span>
                        <span className="text-base">🔥</span>
                     </div>

                     <div className="flex flex-col items-center mb-4">
                        <h3 className="text-2xl font-black font-rabar text-white text-center leading-tight tracking-tight">{draftNickname || 'یاریکەر'}</h3>
                     </div>
                     <div className="grid grid-cols-3 gap-2 px-1" dir="ltr" style={{ color: level < 10 ? '#fff' : level < 25 ? '#1e293b' : level < 45 ? '#451a03' : '#000' }}>
                        <div
                           className="flex flex-col items-center justify-center py-2.5 px-1 rounded-xl border border-white/10 transition-colors duration-500"
                           style={{ backgroundColor: tier.stop1 + '20', borderColor: tier.stop1 + '30' }}
                        >
                           <span className="text-[8px] font-black uppercase mb-0.5 opacity-60" style={{ color: tier.stop1 }}>XP</span>
                           <span className="text-lg font-black leading-none tracking-tighter text-white">{toKuDigits(currentXP)}</span>
                        </div>

                        <div
                           className="flex flex-col items-center justify-center py-2.5 px-1 rounded-xl shadow-lg border-2 z-10 transition-all duration-500 scale-105"
                           style={{
                              backgroundColor: tier.stop1,
                              borderColor: 'rgba(255,255,255,0.2)',
                              boxShadow: `0 10px 20px -5px ${tier.shadow}`
                           }}
                        >
                           <span className="text-[8px] font-black uppercase mb-0.5" style={{ color: level < 25 ? 'rgba(0,0,0,0.5)' : 'rgba(255,255,255,0.6)' }}>ڕێژە</span>
                           <span className="text-xl font-black leading-none">{toKuDigits(Math.round(effectiveProgress * 100))}</span>
                        </div>

                        <div
                           className="flex flex-col items-center justify-center py-2.5 px-1 rounded-xl border border-white/10 relative overflow-hidden group transition-colors duration-500"
                           style={{ backgroundColor: tier.stop1 + '20', borderColor: tier.stop1 + '30' }}
                        >
                           {userRank === 1 && (
                              <div className="absolute inset-0 bg-white/10 animate-pulse"></div>
                           )}
                           <span className="text-[8px] font-black uppercase mb-0.5 opacity-60" style={{ color: tier.stop1 }}>ڕێزبەندی</span>
                           <span className={`text-lg font-black leading-none tracking-tighter text-white`}>
                              #{toKuDigits(userRank || 1)}
                           </span>
                        </div>
                     </div>
                  </div>
               </div>
            </div>
         </div>

         <div className="mx-6 mb-4">
            <div className="flex p-1 rounded-md border shadow-sm relative overflow-hidden transition-all"
               style={{ backgroundColor: 'rgb(203, 213, 225)', borderColor: 'rgba(255, 255, 255, 0.2)' }}>
               {[
                  { id: 'profile', label: 'بەرپەڕ', icon: 'person' },
                  { id: 'stats', label: 'ئامار', icon: 'leaderboard' },
                  { id: 'friends', label: 'ھەڤال', icon: 'group' }
               ].map(tab => {
                  const isActive = activeTab === tab.id;
                  return (
                     <button
                        key={tab.id}
                        onClick={() => { triggerHaptic(10); setActiveTab(tab.id); }}
                        className={`flex-1 relative py-2.5 rounded-md flex items-center justify-center gap-2 transition-all duration-300 z-10 ${isActive
                           ? 'text-white'
                           : 'text-slate-500 hover:text-slate-700'
                           }`}
                     >
                        {isActive && (
                           <motion.div
                              layoutId="activeTabBadge"
                              className="absolute inset-0 bg-slate-800 rounded-md shadow-sm"
                              transition={{ type: "spring", bounce: 0.1, duration: 0.4 }}
                           />
                        )}
                        <span className={`material-symbols-outlined text-[20px] relative z-10 ${isActive ? 'font-bold' : ''}`}>{tab.icon}</span>
                        <span className="text-xs font-black relative z-10 tracking-tight">{tab.label}</span>
                     </button>
                  );
               })}
            </div>
         </div>

         <div className="flex-1 overflow-y-auto px-4 pb-[80px] scrollbar-hide">
            <AnimatePresence mode="wait">
               {activeTab === 'friends' && (
                  <motion.div key="friends" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="space-y-4">
                     <div className="bg-[#f8fafc] p-6 rounded-lg border border-slate-200 flex flex-col items-center text-center noise-grain shadow-[4px_4px_0px_rgba(0,0,0,0.04)]">
                        <div className="w-14 h-14 rounded-full bg-primary/10 flex items-center justify-center mb-4 shadow-[2px_2px_0px_rgba(0,0,0,0.06)]">
                           <span className="material-symbols-outlined text-2xl text-primary font-bold">person_add</span>
                        </div>
                        <h4 className="text-lg font-black font-body text-slate-900 mb-1">ھەڤالێن خوە داخواز بکە</h4>
                        <p className="text-slate-500 text-[11px] font-bold font-body mb-5 leading-relaxed max-w-[200px]">بۆ ھەڤالێ خوە بھنێرە و پێکڤە یاریێ بکەن بۆ بدەستڤەھینانا خەلاتان</p>
                        <button onClick={() => { triggerHaptic(10); handleInvite(); }} className="w-full bg-primary text-black py-2.5 rounded-md font-black font-body text-sm shadow-md hover:brightness-110 active:scale-95 transition-all">
                           کۆپی کرنا لینکی
                        </button>
                     </div>
                  </motion.div>
               )}

               {activeTab === 'stats' && (
                  <motion.div key="stats" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }}>
                     <StatsView playerStats={playerStats} rank={userRank} userNickname={userNickname} userAvatar={userAvatar} level={level} currentXP={currentXP} onViewChange={onViewChange} />
                  </motion.div>
               )}

               {activeTab === 'profile' && (
                  <motion.div key="profile" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="space-y-6 pt-2">
                     <div className="space-y-2 flex flex-col items-end">
                        <label className="text-[10px] font-bold text-slate-500 px-2 uppercase tracking-widest text-right block w-full mt-1">ناسناڤێ تە</label>
                        <div className="flex items-center gap-2 w-full">
                           <div className="relative w-full">
                              <input
                                 ref={nicknameInputRef}
                                 type="text"
                                 value={draftNickname}
                                 onChange={(e) => setDraftNickname(e.target.value)}
                                 readOnly={isNicknameLocked}
                                 maxLength={20}
                                 className={`w-full h-10 border rounded-md px-4 font-bold font-rabar transition-all pr-10 text-right noise-grain shadow-sm text-[13px] ${isNicknameLocked ? 'bg-slate-100 text-slate-500 border-slate-200 cursor-not-allowed' : 'bg-white text-slate-950 border-slate-200 ring-2 ring-primary/20'}`}
                              />
                              <button onClick={() => { triggerHaptic(10); setIsNicknameLocked(false); setTimeout(() => nicknameInputRef.current?.focus(), 50); }} className={`absolute left-3 top-1/2 -translate-y-1/2 material-symbols-outlined text-[18px] ${isNicknameLocked ? 'text-slate-400 hover:text-primary' : 'text-primary'}`}>{isNicknameLocked ? 'edit' : 'edit_square'}</button>
                           </div>
                           {(draftNickname !== userNickname) && draftNickname.trim() && !saveSuccess && (
                              <motion.button
                                 initial={{ scale: 0.8, opacity: 0 }}
                                 animate={{ scale: 1, opacity: 1 }}
                                 onClick={handleSave}
                                 disabled={draftNickname.length < 8 || draftNickname.length > 15}
                                 className={`h-10 px-3 rounded-md font-black text-[10px] shadow-md whitespace-nowrap transition-all ${draftNickname.length < 8 || draftNickname.length > 15 ? 'bg-slate-300 text-slate-500 opacity-50 cursor-not-allowed' : 'bg-primary text-black'}`}
                              >
                                 پاراستن
                              </motion.button>
                           )}
                        </div>
                        {!isNicknameLocked && (
                           <div className="w-full text-right px-1 mt-1">
                              <AnimatePresence>
                                 {draftNickname.length > 0 && draftNickname.length < 8 && (
                                    <motion.p initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="text-red-500 text-[10px] font-black">نابیت ناسناڤێ تە ژ ٨ پیتان کێمتر بیت</motion.p>
                                 )}

                                 {draftNickname.length > 15 && (
                                    <motion.p initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="text-red-500 text-[10px] font-black">نابیت ناڤێ تە ژ ١٥ پیتان زێدەتر بیت</motion.p>
                                 )}

                              </AnimatePresence>
                           </div>
                        )}
                     </div>

                     <div className="space-y-2 flex flex-col items-end">
                        <label className="text-[10px] font-bold text-slate-500 px-2 uppercase tracking-widest text-right block w-full mt-1">ئیمەیڵێ تە (Gmail)</label>
                        <div className="w-full h-11 bg-slate-100 border border-slate-200 rounded-md px-4 flex items-center justify-end font-bold text-slate-500 text-[13px] noise-grain shadow-sm overflow-hidden mb-1">
                           <span className="truncate">{user?.email || 'جیمایڵ نەتایبەتە'}</span>
                           <span className="material-symbols-outlined text-[18px] mr-2 text-slate-400">mail</span>
                        </div>
                     </div>

                     <div className="space-y-2 flex flex-col items-end">
                        <label className="text-[10px] font-bold text-slate-500 px-1 uppercase tracking-widest text-right block w-full">وەڵات</label>
                        <div className="flex items-center gap-2 w-full">
                           <div className="relative w-full">
                              <button ref={flagButtonRef} onClick={() => { triggerHaptic(10); setIsFlagBoxOpen(!isFlagBoxOpen); }} className={`flex items-center px-3 h-10 rounded-md border transition-all w-full justify-between flex-row-reverse ${isFlagBoxOpen ? 'bg-primary border-primary shadow-md' : 'bg-white border-slate-200/80 shadow-xs hover:bg-slate-50'}`}>
                                 <span className={`material-symbols-outlined text-[16px] transition-transform ${isFlagBoxOpen ? 'rotate-180 text-slate-950' : 'text-slate-400'}`}>expand_more</span>
                                 <div className="flex items-center gap-2">
                                    <FlagBadge countryCode={draftCountryCode} isInKurdistan={draftIsInKurdistan} size="xs" />
                                    <span className="text-[11px] font-black font-rabar tracking-wide text-slate-600">{selectedCountryName}</span>
                                 </div>
                              </button>
                           </div>
                           {(draftCountryCode !== countryCode || draftIsInKurdistan !== isInKurdistan) && !saveSuccess && (
                              <motion.button initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} onClick={handleSave} className="h-10 px-3 bg-primary text-black rounded-md font-black text-[10px] shadow-md whitespace-nowrap">پاراستن</motion.button>
                           )}
                        </div>

                        {isFlagBoxOpen && createPortal(
                           <AnimatePresence mode="wait">
                              <motion.div ref={flagDropdownRef} initial={{ opacity: 0, y: 8, scale: 0.95 }} animate={{ opacity: 1, y: 0, scale: 1 }} exit={{ opacity: 0, y: 8, scale: 0.95 }} style={{ position: 'absolute', top: dropdownCoords.top + 6, left: dropdownCoords.left, width: dropdownCoords.width }} className="bg-slate-50 rounded-xl shadow-xl border border-slate-200 z-[9999] overflow-hidden noise-grain">
                                 <div className="p-1.5 max-h-55 overflow-y-auto no-scrollbar">
                                    <button onClick={() => { triggerHaptic(10); setDraftIsInKurdistan(true); setIsFlagBoxOpen(false); }} className="flex items-center gap-2.5 px-2.5 py-1.5 rounded-lg hover:bg-white w-full">
                                       <FlagBadge isInKurdistan={true} size="xs" />
                                       <span className="flex-1 text-left text-[11px] font-bold font-rabar text-slate-700">کوردستان</span>
                                       {draftIsInKurdistan && <span className="material-symbols-outlined text-[16px] text-primary">check_circle</span>}
                                    </button>
                                    {COUNTRIES.map((country) => (
                                       <button key={country.code} onClick={() => { triggerHaptic(10); setDraftIsInKurdistan(false); setDraftCountryCode(country.code); setIsFlagBoxOpen(false); }} className="flex items-center gap-2.5 px-2.5 py-1.5 rounded-lg hover:bg-white w-full">
                                          <FlagBadge countryCode={country.code} size="xs" />
                                          <span className="flex-1 text-left text-[11px] font-bold font-rabar text-slate-700">{country.name}</span>
                                          {!draftIsInKurdistan && draftCountryCode === country.code && <span className="material-symbols-outlined text-[16px] text-primary">check_circle</span>}
                                       </button>
                                    ))}
                                 </div>
                              </motion.div>
                           </AnimatePresence>,
                           document.body
                        )}
                     </div>

                     <div className="space-y-4">
                        <label className="text-[10px] font-bold text-slate-500 px-4 uppercase tracking-widest text-right block w-full">ھەلبژارتنا ئاڤاتاری</label>
                        <div className="bg-[#f8fafc] border border-slate-200 rounded-xl p-4 noise-grain">
                           <div className="grid grid-cols-4 sm:grid-cols-5 md:grid-cols-8 gap-3 max-h-55 overflow-y-auto pr-1 scrollbar-hide py-2 justify-items-center">
                              {AVATARS.map((avatar) => (
                                 <button key={avatar.id} onClick={() => { triggerHaptic(10); setDraftAvatar(avatar.id); }} className={`w-10 h-10 md:w-12 md:h-12 flex items-center justify-center rounded-full transition-all relative overflow-hidden ${draftAvatar === avatar.id ? 'bg-primary shadow-lg scale-110 z-10' : 'bg-white border border-slate-200'}`}><Avatar src={avatar.id} size="sm" border={false} />{draftAvatar === avatar.id && <div className="absolute -bottom-0.5 -right-0.5 bg-green-500 text-white w-4 h-4 rounded-full flex items-center justify-center border-2 border-white z-20"><span className="material-symbols-outlined text-[10px] font-bold">check</span></div>}</button>
                              ))}
                           </div>
                        </div>
                        <input ref={fileInputRef} type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
                     </div>
                  </motion.div>
               )}
            </AnimatePresence>
         </div>
      </div>
   );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AVATARS } from '../data/avatars';
import Avatar from './Avatar';
import FlagBadge from './FlagBadge';
import { triggerHaptic } from '../utils/haptics';
import { supabase } from '../lib/supabase';
import { FilsIcon } from './CurrencyIcon';
import CoinAnimation from './CoinAnimation';
import { toKuDigits } from '../utils/formatters';
import { useGame } from '../context/GameContext';

const getRankInfo = (level) => {
  if (level >= 50) return { name: 'ئەفسانە', color: 'text-purple-400', border: 'border-purple-500' };
  if (level >= 30) return { name: 'پێشەنگ', color: 'text-amber-400', border: 'border-amber-400' };
  if (level >= 15) return { name: 'پایەبەرز', color: 'text-emerald-400', border: 'border-emerald-500' };
  if (level >= 5) return { name: 'شارەزا', color: 'text-blue-400', border: 'border-blue-500' };
  return { name: 'دەستپێکەر', color: 'text-slate-400', border: 'border-slate-500' };
};

export default function PublicProfileModal({ 
  profile, 
  currentUser,
  onClose, 
  onOpenChat,
  isFriend = false,
  isPending = false,
  isBlocked = false,
  onToggleBlock,
  onActionComplete
}) {
  const [fullData, setFullData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isTop10, setIsTop10] = useState(false);
  const [activeTooltip, setActiveTooltip] = useState(null);
  const [showBlockConfirm, setShowBlockConfirm] = useState(false);
  const [showUnfriendConfirm, setShowUnfriendConfirm] = useState(false);
  const [showCoinAnim, setShowCoinAnim] = useState(false);
  const [rewardAmount, setRewardAmount] = useState(0);
  const [claiming, setClaiming] = useState(false);
  const [relStatus, setRelStatus] = useState(isFriend ? 'friend' : (isPending ? 'pending' : 'none')); // 'none', 'pending', 'friend'
  const [isMe, setIsMe] = useState(false);
  const [internalBlocked, setInternalBlocked] = useState(false);
  const { getLevelData } = useGame();

  useEffect(() => {
    if (!profile?.id) return;
    const loadProfile = async () => {
      const { data } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', profile.id)
        .single();

      if (data) setFullData(data);

      // Check Top 10 Globally
      const { data: topPlayers } = await supabase
        .from('profiles')
        .select('id')
        .order('xp', { ascending: false })
        .limit(10);

      if (topPlayers) {
        setIsTop10(topPlayers.some(p => p.id === profile.id));
      }

      // 3. Check Relationship if not same user
      const currentUserId = currentUser?.id;
      if (currentUserId === profile.id) {
        setIsMe(true);
      } else if (currentUserId) {
        // More robust friendship check
        const { data: friendship } = await supabase
          .from('friendships')
          .select('status, user_id, friend_id')
          .or(`and(user_id.eq.${currentUserId},friend_id.eq.${profile.id}),and(user_id.eq.${profile.id},friend_id.eq.${currentUserId})`)
          .maybeSingle();

        if (friendship) {
          if (friendship.status === 'accepted') {
            setRelStatus('friend');
          } else {
            // Check direction for pending status
            setRelStatus(friendship.user_id === currentUserId ? 'pending_sent' : 'pending_received');
          }
        } else {
          setRelStatus('none');
        }

        // 4. Check Block Status - Hardened against 403 errors
        try {
          const { data: block, error: blockError } = await supabase
            .from('blocks')
            .select('id')
            .eq('blocker_id', currentUserId)
            .eq('blocked_id', profile.id)
            .maybeSingle();

          if (blockError) {
            console.warn("Block table access restricted (RLS):", blockError.message);
            setInternalBlocked(false);
          } else {
            setInternalBlocked(!!block);
          }
        } catch (e) {
          console.warn("Social permissions check failed:", e);
          setInternalBlocked(false);
        }
      }

      setLoading(false);
    };
    loadProfile();
  }, [profile?.id, currentUser?.id]);

  if (!profile) return null;

  const displayData = fullData || profile;

  // Exponential Progress Logic (Standardized)
  const levelData = getLevelData(displayData.xp || 0);
  const safeLevel = levelData.level;
  const progressRatio = levelData.progressPercent;
  const nextLevelXP = Math.round(levelData.nextLevelBase);

  // Online Status Logic: Consider online if active in the last 3 minutes
  const isOnline = isMe || (displayData.updated_at && (new Date() - new Date(displayData.updated_at)) < 3 * 60 * 1000);

  // Mastery Logic
  const getMastery = (d) => {
    const modes = [
      { id: 'classic', count: d.mode_classic_played || 0, color: 'text-yellow-400', bg: 'bg-yellow-400/30', icon: 'sports_esports', name: 'پەیڤچنا کلاسیك', shadow: 'shadow-[0_0_15px_rgba(250,204,21,0.6)]' },
      { id: 'lightning', count: d.mode_lightning_played || 0, color: 'text-purple-400', bg: 'bg-purple-400/30', icon: 'bolt', name: 'تایا پەیڤان', shadow: 'shadow-[0_0_15px_rgba(192,132,252,0.6)]' },
      { id: 'hard', count: d.mode_hard_played || 0, color: 'text-orange-500', bg: 'bg-orange-500/30', icon: 'military_tech', name: 'پەیڤێن دژوار', shadow: 'shadow-[0_0_15px_rgba(249,115,22,0.6)]' },
      { id: 'mystery', count: d.mode_mystery_played || 0, color: 'text-sky-500', bg: 'bg-sky-500/30', icon: 'search', name: 'پەیڤا نەھێنی', shadow: 'shadow-[0_0_15px_rgba(14,165,233,0.6)]' }
    ];

    const dominant = modes.reduce((prev, current) => (prev.count > current.count) ? prev : current);

    // Only show if played at least once
    if (dominant.count === 0) return null;

    let tierLevel = 1; // Bronze
    let tierBorder = 'border-amber-700';
    let tierGlow = '';

    if (dominant.count >= 200) {
      tierLevel = 3; // Gold
      tierBorder = 'border-yellow-400';
      tierGlow = dominant.shadow;
    } else if (dominant.count >= 50) {
      tierLevel = 2; // Silver
      tierBorder = 'border-slate-300';
    }

    return { ...dominant, tierLevel, tierBorder, tierGlow };
  };

  const handleClaimMastery = async () => {
    if (!mastery || claiming) return;
    const isMe = currentUser?.id === displayData.id;
    if (!isMe) return;

    const claimedTier = displayData.mastery_claims?.[mastery.id] || 0;
    if (mastery.tierLevel <= claimedTier) return;

    setClaiming(true);
    triggerHaptic(50); // Strong haptic for big claim

    const rewards = { 1: 500, 2: 2500, 3: 10000 };
    const amount = rewards[mastery.tierLevel];

    setRewardAmount(amount);

    // Update DB
    const newClaims = { 
      ...(displayData.mastery_claims || {}), 
      [mastery.id]: mastery.tierLevel 
    };

    const { error } = await supabase
      .from('profiles')
      .update({ 
        shayi: (displayData.shayi || 0) + amount,
        mastery_claims: newClaims
      })
      .eq('id', currentUser?.id);

    if (!error) {
      setFullData({ ...displayData, shayi: (displayData.shayi || 0) + amount, mastery_claims: newClaims });
      setShowCoinAnim(true);
      setTimeout(() => setShowCoinAnim(false), 3500);
    }
    setClaiming(false);
  };

  const handleSendFriendRequest = async () => {
    if (!currentUser || relStatus !== 'none') return;
    triggerHaptic(15);
    setRelStatus('pending_sent'); // Optimistic UI

    const { error } = await supabase
      .from('friendships')
      .insert([{ user_id: currentUser?.id, friend_id: profile.id, status: 'pending' }]);

    if (error) {
      if (error.code === '23505') {
        // Already sent, keep the optimistic status
        if (onActionComplete) onActionComplete();
        return;
      }
      setRelStatus('none');
      console.error("Friend request error:", error);
    } else {
      if (onActionComplete) onActionComplete();
    }
  };

  const handleAcceptFriendRequest = async () => {
    if (!currentUser || relStatus !== 'pending_received') return;
    triggerHaptic(20);
    setRelStatus('friend'); // Optimistic

    const { error } = await supabase
      .from('friendships')
      .update({ status: 'accepted' })
      .or(`and(user_id.eq.${currentUser?.id},friend_id.eq.${profile.id}),and(user_id.eq.${profile.id},friend_id.eq.${currentUser?.id})`);

    if (error) {
      setRelStatus('pending_received');
      console.error("Accept error:", error);
    } else {
      if (onActionComplete) onActionComplete();
    }
  };

  const handleDeclineFriendRequest = async () => {
    if (!currentUser) return;
    triggerHaptic(10);
    setRelStatus('none'); // Optimistic

    const { error } = await supabase
      .from('friendships')
      .delete()
      .or(`and(user_id.eq.${currentUser?.id},friend_id.eq.${profile.id}),and(user_id.eq.${profile.id},friend_id.eq.${currentUser?.id})`);

    if (error) {
      console.error("Decline error:", error);
    } else {
      if (onActionComplete) onActionComplete();
    }
  };

  const handleUnfriend = async () => {
    if (!currentUser || relStatus !== 'friend') return;

    const { error } = await supabase
      .from('friendships')
      .delete()
      .or(`and(user_id.eq.${currentUser?.id},friend_id.eq.${profile.id}),and(user_id.eq.${profile.id},friend_id.eq.${currentUser?.id})`);

    if (!error) {
      setRelStatus('none');
      setShowUnfriendConfirm(false);
      triggerHaptic(30);
      if (onActionComplete) onActionComplete();
    } else {
      console.error("Unfriend error:", error);
    }
  };

  const mastery = getMastery(displayData);

  // Medals Configuration
  const medals = [
    { id: 'nobera', name: 'نۆبەرە', condition: (d) => (d.level || 1) >= 1, color: 'text-amber-500', glow: 'shadow-[0_0_15px_rgba(245,158,11,0.5)]', icon: 'military_tech', tooltip: 'ئاستێ ١ ب دەستڤە بینە' },
    { id: 'palawan', name: 'پاڵەوان', condition: (d) => (d.games_won || 0) >= 50, color: 'text-red-500', glow: 'shadow-[0_0_15px_rgba(239,68,68,0.5)]', icon: 'sports_mma', tooltip: '٥٠ یارییان ببە دا ببیە پاڵەوان!' },
    { id: 'mamosta', name: 'مامۆستا', condition: (d) => (d.level || 1) >= 20, color: 'text-yellow-400', glow: 'shadow-[0_0_15px_rgba(250,204,21,0.5)]', icon: 'school', tooltip: 'ئاستێ ٢٠ ب دەستڤە بینە' },
    { id: 'shanazi_kurdistan', name: 'شانازیا کوردستانێ', condition: (d) => (d.kurdish_words_completed || 0) >= 100, color: 'text-emerald-500', glow: 'shadow-[0_0_15px_rgba(16,185,129,0.5)]', icon: 'beenhere', tooltip: '١٠٠ پەیڤێن کوردی تەواو بکە' },
    { id: 'shanazi_jihani', name: 'شانازیا جیھانی', condition: (d) => isTop10 && (d.xp || 0) >= 1000, color: 'text-purple-400', glow: 'shadow-[0_0_15px_rgba(192,132,252,0.5)]', icon: 'public', tooltip: 'د ناڤ ١٠ باشترینێن جیھانێ دا بە' },
  ];

  const effectiveIsBlocked = internalBlocked || isBlocked;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 sm:p-12 overflow-hidden pointer-events-auto">
      {/* Heavy Backdrop */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-slate-950/90 backdrop-blur-xl"
      />

      <motion.div
        initial={{ scale: 0.9, opacity: 0, y: 30 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        exit={{ scale: 0.9, opacity: 0, y: 30 }}
        className="relative w-full max-w-sm bg-slate-900 border border-white/10 rounded-[2rem] overflow-hidden shadow-[0_35px_60px_-15px_rgba(0,0,0,0.8)] flex flex-col items-center p-6 text-center max-h-[90vh] overflow-y-auto"
        dir="rtl"
      >
        {/* Deep Golden Glow */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-48 h-48 bg-amber-500/20 rounded-full blur-[80px] -z-10 pointer-events-none" />

        {/* Close Button */}
        <button 
          onClick={onClose} 
          className="absolute top-4 left-4 w-8 h-8 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-white/50 hover:text-white hover:bg-white/10 transition-all z-10"
        >
          <span className="material-symbols-outlined text-[18px]">close</span>
        </button>

        {/* Level Badge - Top Right */}
        <div className="absolute top-4 right-4 z-10">
           <div className="relative w-11 h-12 flex items-center justify-center">
              <svg className="absolute inset-0 w-full h-full drop-shadow-2xl" viewBox="0 0 100 115" fill="none" xmlns="http://www.w3.org/2000/svg">
                 <path d="M50 0L95 20V55C95 80 50 115 50 115C50 115 5 80 5 55V20L50 0Z" fill="url(#medalGradientPublic)" stroke="white" strokeWidth="4" strokeOpacity="0.2" />
                 <defs>
                    <linearGradient id="medalGradientPublic" x1="50" y1="0" x2="50" y2="115" gradientUnits="userSpaceOnUse">
                       <stop stopColor={safeLevel >= 10 ? "#FFD700" : "#94a3b8"} />
                       <stop offset="1" stopColor={safeLevel >= 10 ? "#B8860B" : "#475569"} />
                    </linearGradient>
                 </defs>
              </svg>
              <div className="relative z-10 flex flex-col items-center justify-center -mt-1.5">
                 <span className="text-[7.5px] font-black text-slate-950/40 uppercase leading-none mb-0.5">ئاستێ</span>
                 <span className="text-xl font-black text-slate-950 leading-none drop-shadow-sm">{toKuDigits(safeLevel)}</span>
              </div>
           </div>
        </div>

        {/* Avatar Section */}
        <div className="relative mb-3 mt-2">
          <div className={`w-28 h-28 rounded-full p-1.5 flex items-center justify-center shadow-xl relative ${safeLevel >= 10 ? 'bg-gradient-to-tr from-amber-400 via-yellow-200 to-amber-600' : 'bg-slate-700'}`}>
             <div className="w-full h-full rounded-full bg-slate-900 flex items-center justify-center text-5xl border-[3px] border-slate-900 overflow-hidden relative shadow-inner">
                <Avatar 
                   src={displayData.avatar_url} 
                   updatedAt={displayData.updated_at} 
                   size="2xl" 
                   border={false}
                />
             </div>
          </div>
          {isOnline && (
            <div className="absolute bottom-2 right-2 w-6 h-6 bg-emerald-500 border-4 border-slate-900 rounded-full shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-pulse" />
          )}
        </div>

        {/* Identity Section */}
        <div className="space-y-1 mb-5 flex flex-col items-center">
           <div className="flex items-center justify-center gap-2">
              <h2 className="text-2xl font-black text-white font-rabar">{displayData.nickname}</h2>
              <FlagBadge countryCode={displayData.country_code} isInKurdistan={displayData.is_kurdistan} size="sm" />
           </div>

           {mastery && (
             <div className="relative mt-2 pt-1 flex items-center justify-center gap-2 group">
                <div 
                  className="relative flex items-center justify-center cursor-pointer"
                  onClick={() => triggerHaptic(10)}
                >
                   <motion.div 
                     className={`absolute inset-0 rounded-full ${mastery.bg} ${mastery.tierGlow} blur-sm`}
                     animate={{ scale: [1, 1.25, 1], opacity: [0.4, 0.8, 0.4] }}
                     transition={{ duration: 2.5, repeat: Infinity, ease: "easeInOut" }}
                   />
                   <div className={`relative z-10 flex items-center gap-1.5 px-3 py-1 rounded-full bg-slate-900 border-2 ${mastery.tierBorder} transition-colors`}>
                      <span className={`material-symbols-outlined text-[15px] ${mastery.color}`}>{mastery.icon}</span>
                      <span className={`text-[9px] uppercase tracking-widest font-black font-rabar ${mastery.color}`}>{mastery.name}</span>
                   </div>
                </div>

                {isMe && mastery.tierLevel > (displayData.mastery_claims?.[mastery.id] || 0) && (
                  <motion.button
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    onClick={handleClaimMastery}
                    disabled={claiming}
                    className="relative z-20 flex items-center gap-1 bg-emerald-500 text-slate-950 font-black text-[10px] py-1 px-3 rounded-full shadow-lg border border-emerald-400/50 transition-all hover:bg-emerald-400"
                  >
                    {claiming ? '...' : 'وەرگرتن'}
                    <FilsIcon className="w-3.5 h-3.5" />
                  </motion.button>
                )}
             </div>
           )}
        </div>

        {/* Stats Grid */}
        {!loading && (
          <motion.div 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="w-full mb-5 pt-4 border-t border-white/5 space-y-4"
          >
             <div className="w-full relative overflow-hidden px-2">
                <div className="flex justify-between items-end mb-1.5 relative z-10">
                   <div className="text-right">
                     <span className="text-[8px] font-black font-ui uppercase tracking-widest text-white/40 block">ئەزموون (XP)</span>
                     <span className="text-base font-black text-white font-ui">{displayData.xp || 0}</span>
                   </div>
                   <span className="text-[9px] font-black text-white/20">/ {nextLevelXP}</span>
                </div>
                <div className="w-full h-2 bg-slate-950 rounded-full overflow-hidden shadow-inner relative z-10">
                   <motion.div 
                     initial={{ width: 0 }}
                     animate={{ width: `${progressRatio}%` }}
                     transition={{ duration: 1, ease: "easeOut", delay: 0.2 }}
                     className="h-full bg-gradient-to-r from-amber-600 to-amber-400 rounded-full"
                   />
                </div>
             </div>

             <div className="grid grid-cols-2 gap-3">
                <div className="bg-white/5 border border-white/5 p-3 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden group">
                   <span className="text-[8px] font-black text-white/30 uppercase tracking-widest mb-1 font-ui">باڵانس</span>
                   <div className="flex items-center gap-1.5">
                      <div className="flex flex-col items-end leading-none translate-y-0.5">
                         <span className="text-xl font-black text-white font-ui">{toKuDigits(displayData.shayi || 0)}</span>
                         <span className="text-[8px] font-black uppercase tracking-widest opacity-60 text-white/40">فلس</span>
                      </div>
                      <FilsIcon className="w-4 h-4" />
                   </div>
                </div>
                <div className="bg-white/5 border border-white/5 p-3 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden group">
                   <span className="text-[8px] font-black text-white/30 uppercase tracking-widest mb-1 font-ui">ستریك</span>
                   <div className="flex items-center gap-1.5">
                      <span className="text-xl font-black text-white font-ui">{toKuDigits(displayData.daily_streak || 0)}</span>
                      <span className="text-lg">🔥</span>
                   </div>
                </div>
             </div>

             <div className="pt-2 border-t border-white/5">
                <span className="text-[8px] font-black text-white/30 uppercase tracking-widest block text-center mb-3">دەستکەڤت و مەدالیا</span>
                <div className="flex justify-center gap-2 flex-wrap relative">
                   {medals.map((m, idx) => {
                     const isUnlocked = m.condition(displayData);
                     return (
                       <div key={m.id} className="relative">
                         <button 
                           onClick={() => {
                             triggerHaptic(10);
                             setActiveTooltip(activeTooltip === m.id ? null : m.id);
                             if(activeTooltip !== m.id) setTimeout(() => setActiveTooltip(null), 3000);
                           }}
                           className={`w-11 h-11 rounded-full border-[1.5px] flex flex-col items-center justify-center transition-all duration-500 overflow-hidden relative
