                          <Avatar 
                            src={chat.avatar_url} 
                            lastActive={chat.updated_at} 
                            showStatus={true} 
                            size="md" 
                            border={false}
                            className="transition-all" 
                          />
                        </div>

                        {/* Name and Message */}
                        <div className="flex flex-col items-start min-w-0">
