      </div>

      {/* Public Profile Modal */}
      <AnimatePresence>
        {selectedPlayer && (
          <PublicProfileModal 
            profile={selectedPlayer} 
            currentUser={user}
            isFriend={friends.some(f => f.friend?.id === selectedPlayer.id)}
            isPending={pendingRequests.some(r => r.sender?.id === selectedPlayer.id || r.friend_id === selectedPlayer.id)}
