import React, { createContext, useContext, useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { playSuccessSfx, playPopSfx, playNotifSfx, playMessageSfx, playGameStartSfx, playCoinSfx } from '../utils/audio';

const GameContext = createContext();

export const GameProvider = ({ children }) => {
  const [level, setLevel] = useState(1);
  const [lastNotifiedLevel, setLastNotifiedLevel] = useState(1);
  const [winsTowardsSecret, setWinsTowardsSecret] = useState(0);
  const [currentXP, setCurrentXP] = useState(0);
  const [dailyStreak, setDailyStreak] = useState(0);
  const [appSoundsEnabled, setAppSoundsEnabled] = useState(() => {
    const saved = localStorage.getItem('peyvchin_app_sounds');
    return saved !== null ? saved === 'true' : true;
  });
  const [hapticEnabled, setHapticEnabled] = useState(() => {
    const saved = localStorage.getItem('peyvchin_haptic_enabled');
    return saved !== null ? saved === 'true' : true;
  });
  const [user, setUser] = useState(null);
   const [loading, setLoading] = useState(true);
   const [userRank, setUserRank] = useState(1);
   const [inventory, setInventory] = useState({ badges: [] });
 


  // INVENTORY STATE (Robust Initialization)
  const getInitial = (key, fallback) => {
    const saved = localStorage.getItem(key);
    return (saved !== null) ? Number(saved) : fallback;
  };

  const [fils, setFils] = useState(() => getInitial('peyvchin_fils', 1000));
  const [derhem, setDerhem] = useState(() => getInitial('peyvchin_derhem', 50));
  const [zer, setZer] = useState(() => getInitial('peyvchin_zer', 5));
  const [magnetCount, setMagnetCount] = useState(() => getInitial('peyvchin_magnets', 3));
  const [hintCount, setHintCount] = useState(() => getInitial('peyvchin_hints', 5));
  const [skipCount, setSkipCount] = useState(() => getInitial('peyvchin_skips', 2));

  // EXTENDED PLAYER DATA (Everything Connected)
  const [userNickname, setUserNickname] = useState('یاریزان');
  const [userAvatar, setUserAvatar] = useState('default');
  const [city, setCity] = useState('');
  const [isInKurdistan, setIsInKurdistan] = useState(true);
  const [countryCode, setCountryCode] = useState('IQ');
  const [ownedAvatars, setOwnedAvatars] = useState(['default']);
  const [unlockedThemes, setUnlockedThemes] = useState(['default']);
  const [currentTheme, setCurrentTheme] = useState('default');
  const [solvedWords, setSolvedWords] = useState([]);
  const [playerStats, setPlayerStats] = useState({
    classic: { bestStreak: 0, currentStreak: 0, totalCorrect: 0 },
    mamak: { totalCorrect: 0 },
    hard: { totalCorrect: 0 },
    wordFever: { bestTime: 0, totalWins: 0 }
  });

  /**
   * EXPONENTIAL PROGRESSION FORMULA
   * Base: 500, Factor: 1.1 (10% increase per level)
   */
  const LEVEL_BASE_XP = 500;
  const LEVEL_FACTOR = 1.1;

  const getLevelFromXP = (xp) => {
    if (xp <= 0) return 1;
    return Math.floor(Math.log(xp * (LEVEL_FACTOR - 1) / LEVEL_BASE_XP + 1) / Math.log(LEVEL_FACTOR)) + 1;
  };

  const getLevelData = (xp) => {
    const level = getLevelFromXP(xp);
    const currentLevelBase = LEVEL_BASE_XP * (Math.pow(LEVEL_FACTOR, level - 1) - 1) / (LEVEL_FACTOR - 1);
    const nextLevelBase = LEVEL_BASE_XP * (Math.pow(LEVEL_FACTOR, level) - 1) / (LEVEL_FACTOR - 1);
    const levelWidth = nextLevelBase - currentLevelBase;
    const progressInLevel = xp - currentLevelBase;
    const progressPercent = levelWidth > 0 ? (progressInLevel / levelWidth) * 100 : 0;
    
    return {
      level,
      currentLevelBase,
      nextLevelBase,
      progressInLevel,
      levelWidth,
      progressPercent: Math.min(100, Math.max(0, progressPercent))
    };
  };
  
  const levelData = getLevelData(currentXP);
  const minXPForLevel = levelData.currentLevelBase;
  const maxXP = levelData.nextLevelBase;


  const lastRefreshTime = useRef(0);
  const lastXPRef = useRef(-1);

  const refreshRank = async (xpValue = currentXP) => {
    // 1. Guard: If value hasn't changed AND we refreshed very recently (< 2s), skip
    const now = Date.now();
    if (xpValue === lastXPRef.current && (now - lastRefreshTime.current < 2000)) {
       return;
    }

    try {
      lastRefreshTime.current = now;
      lastXPRef.current = xpValue;

      // Query how many users have MORE xp than current user
      const { count, error } = await supabase
        .from('profiles')
        .select('id', { count: 'exact', head: true })
        .gt('xp', xpValue);

      if (!error && count !== null) {
        setUserRank(count + 1);
      }
    } catch (err) {
      console.warn("Rank refresh failed:", err);
    }
  };

  // 1. DATA SYNCHRONIZATION LIFECYCLE
  useEffect(() => {
    const initializeSession = async () => {
      // Get current session
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        setUser(session.user);
        await syncProfile(session.user.id);
      } else {
        // Fallback to local storage for guests
        const localXP = localStorage.getItem('peyvchin_xp');
        const localLvl = localStorage.getItem('peyvchin_level');
        const localNotifiedLvl = localStorage.getItem('peyvchin_last_notified_level');
        const localUnlockProgress = localStorage.getItem('peyvchin_wins_towards_secret');
        
        if (localXP) setCurrentXP(parseFloat(localXP));
        if (localLvl) setLevel(parseInt(localLvl));
        if (localNotifiedLvl) setLastNotifiedLevel(parseInt(localNotifiedLvl));
        if (localUnlockProgress) setWinsTowardsSecret(parseInt(localUnlockProgress));
        
        // Sync items
        setFils(getInitial('peyvchin_fils', 1000));
        setDerhem(getInitial('peyvchin_derhem', 50));
        setZer(getInitial('peyvchin_zer', 5));
        setMagnetCount(getInitial('peyvchin_magnets', 3));
        setHintCount(getInitial('peyvchin_hints', 5));
        setSkipCount(getInitial('peyvchin_skips', 2));
      }
      setLoading(false);
    };

    const syncProfile = async (userId) => {
      try {
        let data, error;
        try {
          // 1. Primary Attempt: All Premium Columns
          const columns = 'level, xp, last_notified_level, wins_towards_secret, shayi, dirham, dinar, magnets, hints, skips, daily_streak, inventory, app_sounds_enabled, haptic_enabled, nickname, avatar_url, city, is_kurdistan, country_code, updated_at';
          
          let result = await supabase.from('profiles').select(columns).eq('id', userId).single();
          
          // 2. Defensive Fallback: If 42703 (Undefined Column) occurs, fetch only 100% Core columns
          if (result.error && result.error.code === '42703') {
            console.warn("Detection of missing columns in Supabase. Falling back to Core Select.");
            const coreColumns = 'level, xp, last_notified_level, shayi, magnets, hints, skips'; // Basics that must exist
            result = await supabase.from('profiles').select(coreColumns).eq('id', userId).single();
          }

          data = result.data;
          error = result.error;
        } catch (fetchError) {
          console.warn("Supabase fetch fatal error:", fetchError);
          return;
        }

        if (error && error.code === 'PGRST116') {
          const initialRecord = {
            id: userId, level: 1, xp: 0, last_notified_level: 1,
            shayi: 1000, dirham: 50, dinar: 5,
            magnets: 3, hints: 5, skips: 2,
            inventory: {
              badges: [],
              owned_avatars: ['default'],
              unlocked_themes: ['default'],
              equipped_theme: 'default',
              solved_words: [],
              stats: { classic: { bestStreak: 0, totalCorrect: 0 } }
            },
            daily_streak: 0,
            updated_at: new Date().toISOString()
          };
          await supabase.from('profiles').insert([initialRecord]);
          setFils(1000); setMagnetCount(3); setHintCount(5); setSkipCount(2); setDailyStreak(0);
        } else if (data && !error) {
          // Safe Data Mapping (Try/Catch per field)
          const safeSet = (setter, val, fallback) => {
            try { setter(val ?? fallback); } catch(e) { console.warn("Mapping failed for field", e); }
          };

          safeSet(setLevel, data.level, 1);
          safeSet(setWinsTowardsSecret, data.wins_towards_secret, 0);
          safeSet(setCurrentXP, data.xp, 0);
          safeSet(setFils, data.shayi, 1000);
          safeSet(setDerhem, data.dirham, 50);
          safeSet(setZer, data.dinar, 5);
          safeSet(setMagnetCount, data.magnets, 3);
          safeSet(setHintCount, data.hints, 5);
          safeSet(setSkipCount, data.skips, 2);
          safeSet(setDailyStreak, data.daily_streak, 0);
          safeSet(setLastNotifiedLevel, data.last_notified_level, 1);
          
          // Safety fallback for sound/haptic columns
          setAppSoundsEnabled(data.app_sounds_enabled !== undefined ? data.app_sounds_enabled : (localStorage.getItem('peyvchin_app_sounds') === 'true'));
          setHapticEnabled(data.haptic_enabled !== undefined ? data.haptic_enabled : (localStorage.getItem('peyvchin_haptic_enabled') === 'true'));
          
          // Extended Data
          setUserNickname(data.nickname || 'یاریزان');
          setUserAvatar(data.avatar_url || 'default');
          setCity(data.city || '');
          setIsInKurdistan(data.is_kurdistan ?? true);
          setCountryCode(data.country_code || 'IQ');

          const inv = data.inventory || {};
          setInventory(inv);
          if (inv.owned_avatars) setOwnedAvatars(inv.owned_avatars);
          if (inv.unlocked_themes) setUnlockedThemes(inv.unlocked_themes);
          if (inv.solved_words) setSolvedWords(inv.solved_words);
          if (inv.stats) setPlayerStats(inv.stats);
          if (inv.equipped_theme) setCurrentTheme(inv.equipped_theme);
          

          // Daily Streak Logic
          const today = new Date().toISOString().split('T')[0];
          const lastLoginDate = inv.last_login;
          let newStreak = data.daily_streak || 0;

          if (!lastLoginDate) {
            newStreak = 1;
            updateProfile({ playerStats: { ...inv.stats, last_login: today }, dailyStreak: 1 });
          } else if (lastLoginDate !== today) {
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayStr = yesterday.toISOString().split('T')[0];

            if (lastLoginDate === yesterdayStr) {
               newStreak += 1;
            } else {
               newStreak = 1;
            }
            
            // Persist the new streak and update login date
            const nextInv = { ...inv, last_login: today };
            setInventory(nextInv);
            setDailyStreak(newStreak);
            
            // Sync to DB
            supabase.from('profiles').update({ 
               daily_streak: newStreak,
               inventory: nextInv,
               updated_at: new Date().toISOString()
            }).eq('id', userId).then();
          } else {
            setDailyStreak(newStreak);
          }
          
          localStorage.setItem('peyvchin_skips', (data.skips ?? 2).toString());
          localStorage.setItem('peyvchin_daily_streak', (data.daily_streak ?? 0).toString());
          localStorage.setItem('peyvchin_app_sounds', (data.app_sounds_enabled ?? true).toString());
          localStorage.setItem('peyvchin_haptic_enabled', (data.haptic_enabled ?? true).toString());
          
          refreshRank(data.xp || 0);
        }
      } catch (err) {
        console.warn("Profile Sync Error:", err);
      }
    };
 


    initializeSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) syncProfile(session.user.id);
    });

    return () => subscription.unsubscribe();
  }, []);

  // ONLINE HEARTBEAT
  useEffect(() => {
    if (!user) return;
    const heartbeat = setInterval(async () => {
      try {
        await supabase.from('profiles').update({ updated_at: new Date().toISOString() }).eq('id', user.id);
      } catch(e) {}
    }, 60000);
    return () => clearInterval(heartbeat);
  }, [user]);

  /**
   * syncProgressToDatabase (NEW XP & STREAK SYSTEM)
   * Uses handle_game_xp RPC for atomic progression sync.
   */

  /**
   * processLevelCompletion (LEGACY - Kept for compatibility if needed)
   */
  const processLevelCompletion = async (baseReward, xp, gameMode = 'classic', completedLevel = null) => {
    // We now prefer syncProgressToDatabase for primary game loops
    const multipliers = {
      'hard_words': 2.0,
      'secret_word': 2.5,
      'mamak': 1.5,
      'word_fever': 1.25,
      'classic': 1.0
    };
    const multiplier = multipliers[gameMode] || 1.0;
    const reward = Math.ceil(baseReward * multiplier);

    setFils(prev => prev + reward);
    
    setCurrentXP(prevXP => {
      const nextXP = prevXP + xp;
      // Level increment is handled by the useEffect above
      return nextXP;
    });
    
    if (user) {
      await supabase.rpc('handle_level_completion', {
        p_user_id: user.id,
        p_reward_amount: Math.ceil(baseReward),
        p_xp_amount: xp,
        p_game_mode: gameMode,
        p_completed_level: completedLevel
      });
    }
  };

  const addXP = useCallback((amount) => {
    if (!amount) return;
    const { user: currentUser } = stateRef.current;
    setCurrentXP(prev => {
      const next = prev + amount;
      localStorage.setItem('peyvchin_xp', next.toString());
      if (currentUser) {
        supabase.from('profiles').update({ xp: next }).eq('id', currentUser.id).then();
      }
      return next;
    });
  }, []);

  // --- STABILIZATION REFS ---
  // We mirror state in refs to allow actions to have [] dependencies
  const stateRef = useRef({ fils, derhem, zer, magnetCount, hintCount, skipCount, user, currentXP, level, inventory });
  useEffect(() => {
    stateRef.current = { fils, derhem, zer, magnetCount, hintCount, skipCount, user, currentXP, level, inventory };
  }, [fils, derhem, zer, magnetCount, hintCount, skipCount, user, currentXP, level, inventory]);

  const playPopSound = useCallback((bypassDebounce = false) => {
    playPopSfx(appSoundsEnabled, bypassDebounce);
  }, [appSoundsEnabled]);

  const playNotifSound = useCallback(() => {
    playNotifSfx(appSoundsEnabled);
  }, [appSoundsEnabled]);

  const playMessageSound = useCallback(() => {
    playMessageSfx(appSoundsEnabled);
  }, [appSoundsEnabled]);

  const playStartSound = useCallback(() => {
    playGameStartSfx(appSoundsEnabled);
  }, [appSoundsEnabled]);

  const playVictorySound = useCallback(() => {
    playSuccessSfx(appSoundsEnabled);
  }, [appSoundsEnabled]);

  const playRewardSound = useCallback(() => {
    playCoinSfx(appSoundsEnabled);
  }, [appSoundsEnabled]);

  /**
   * updateInventory ACTION (STABILIZED)
   */
  const updateInventory = useCallback(async (updates, isAdditive = true) => {
    // 1. captures previous values for local storage consistency
    const getLocalVal = (key, fallback) => {
      const saved = localStorage.getItem(key);
      return saved !== null ? Number(saved) : fallback;
    };

    // 2. Perform state updates using the functional pattern
    if (updates.fils !== undefined) setFils(prev => isAdditive ? prev + updates.fils : updates.fils);
    if (updates.derhem !== undefined) setDerhem(prev => isAdditive ? prev + updates.derhem : updates.derhem);
    if (updates.zer !== undefined) setZer(prev => isAdditive ? prev + updates.zer : updates.zer);
    if (updates.magnetCount !== undefined) setMagnetCount(prev => isAdditive ? prev + updates.magnetCount : updates.magnetCount);
    if (updates.hintCount !== undefined) setHintCount(prev => isAdditive ? prev + updates.hintCount : updates.hintCount);
    if (updates.skipCount !== undefined) setSkipCount(prev => isAdditive ? prev + updates.skipCount : updates.skipCount);

    // 3. Persistent Local Storage Sync
    Object.entries(updates).forEach(([key, val]) => {
      const storageKey = key === 'magnetCount' ? 'peyvchin_magnets' : key === 'hintCount' ? 'peyvchin_hints' : key === 'skipCount' ? 'peyvchin_skips' : `peyvchin_${key}`;
      const fallback = key === 'fils' ? 250 : key === 'derhem' ? 50 : key === 'zer' ? 5 : key === 'magnetCount' ? 1 : key === 'hintCount' ? 2 : 1;
      const current = getLocalVal(storageKey, fallback);
      const finalVal = isAdditive ? (current + val) : val;
      localStorage.setItem(storageKey, finalVal.toString());
    });

    // 4. Remote Database Sync (Supabase) - Reading from Ref for stability
    const { user: currentUser, fils: currFils, derhem: currDerhem, zer: currZer, magnetCount: currMags, hintCount: currHints, skipCount: currSkips } = stateRef.current;
    
    if (currentUser) {
      const dbUpdates = {};
      if (updates.fils !== undefined) dbUpdates.shayi = isAdditive ? (currFils + updates.fils) : updates.fils;
      if (updates.derhem !== undefined) dbUpdates.dirham = isAdditive ? (currDerhem + updates.derhem) : updates.derhem;
      if (updates.zer !== undefined) dbUpdates.dinar = isAdditive ? (currZer + updates.zer) : updates.zer;
      if (updates.magnetCount !== undefined) dbUpdates.magnets = isAdditive ? (currMags + updates.magnetCount) : updates.magnetCount;
      if (updates.hintCount !== undefined) dbUpdates.hints = isAdditive ? (currHints + updates.hintCount) : updates.hintCount;
      if (updates.skipCount !== undefined) dbUpdates.skips = isAdditive ? (currSkips + updates.skipCount) : updates.skipCount;
      dbUpdates.updated_at = new Date().toISOString();

      try {
        await supabase.from('profiles').update(dbUpdates).eq('id', currentUser.id);
      } catch (err) {
        console.warn("DB Inventory Sync Failed:", err);
      }
    }
  }, []); // IDENTITY STABLE

  /**
   * syncProgressToDatabase (STABILIZED)
   */
  const syncProgressToDatabase = useCallback(async (lettersCount, gameMode = 'classic', additionalData = {}) => {
    const { user: currentUser, currentXP: currXP, level: currLevel, inventory: currInv } = stateRef.current;
    if (!currentUser?.id) return null;

    try {
      const { data, error } = await supabase.rpc('handle_game_xp', {
        p_user_id: currentUser.id,
        p_letters_count: lettersCount,
        p_shayi_bonus: additionalData.shayiBonus || 5
      });

      if (error) throw error;

      if (data) {
        const { new_level, xp_added, current_streak } = data;
        const finalXP = (currXP || 0) + xp_added;

        const profileUpdates = { updated_at: new Date().toISOString() };
        if (additionalData.solvedWords) profileUpdates.inventory = { ...currInv, solved_words: additionalData.solvedWords };
        if (additionalData.winsTowardsSecret !== undefined) profileUpdates.wins_towards_secret = additionalData.winsTowardsSecret;
        if (additionalData.resetSecretProgress) profileUpdates.wins_towards_secret = 0;

        await supabase.from('profiles').update(profileUpdates).eq('id', currentUser.id);

        setCurrentXP(finalXP);
        setDailyStreak(current_streak);
        if (additionalData.solvedWords) setSolvedWords(additionalData.solvedWords);
        if (additionalData.winsTowardsSecret !== undefined) setWinsTowardsSecret(additionalData.winsTowardsSecret);
        if (additionalData.resetSecretProgress) setWinsTowardsSecret(0);
        
        if (new_level > currLevel) {
          setLevel(new_level);
          refreshRank(finalXP);
        } else {
          refreshRank(finalXP);
        }

        return {
          xpAdded: xp_added,
          currentStreak: current_streak,
          newLevel: new_level,
          bahdiniMsg: current_streak > 1 ? `ستریکێن تە: ${current_streak} ڕۆژ 🔥` : `دەستپێکرنەکا باشە! ✨`
        };
      }
    } catch (err) {
      console.error("XP Sync Failed:", err.message);
      return null;
    }
    return null;
  }, []);

  /**
   * incrementSecretWordProgress (STABILIZED)
   */
  const incrementSecretWordProgress = useCallback(async () => {
    const { user: currentUser } = stateRef.current;
    setWinsTowardsSecret(prev => {
      const next = Math.min(3, prev + 1);
      localStorage.setItem('peyvchin_wins_towards_secret', next.toString());
      if (currentUser) {
        supabase.from('profiles').update({ wins_towards_secret: next }).eq('id', currentUser.id).then();
      }
      return next;
    });
  }, []);

  const resetSecretWordProgress = useCallback(async () => {
    const { user: currentUser } = stateRef.current;
    setWinsTowardsSecret(0);
    localStorage.setItem('peyvchin_wins_towards_secret', '0');
    if (currentUser) {
      await supabase.from('profiles').update({ wins_towards_secret: 0 }).eq('id', currentUser.id);
    }
  }, []);

  const updateProfile = useCallback(async (profileData) => {
    const { user: currentUser, inventory: currInv } = stateRef.current;
    if (!currentUser?.id) return;

    if (profileData.nickname !== undefined) setUserNickname(profileData.nickname);
    if (profileData.avatar_url !== undefined) setUserAvatar(profileData.avatar_url);
    if (profileData.city !== undefined) setCity(profileData.city);
    if (profileData.is_kurdistan !== undefined) setIsInKurdistan(profileData.is_kurdistan);
    if (profileData.country_code !== undefined) setCountryCode(profileData.country_code);

    const dbUpdates = {};
    if (profileData.lastNotifiedLevel !== undefined) {
      dbUpdates.last_notified_level = profileData.lastNotifiedLevel;
      setLastNotifiedLevel(profileData.lastNotifiedLevel);
    }
    if (profileData.nickname !== undefined) dbUpdates.nickname = profileData.nickname.trim();
    if (profileData.avatar_url !== undefined) dbUpdates.avatar_url = profileData.avatar_url;
    if (profileData.city !== undefined) dbUpdates.city = profileData.city;
    if (profileData.is_kurdistan !== undefined) dbUpdates.is_kurdistan = profileData.is_kurdistan;
    if (profileData.country_code !== undefined) dbUpdates.country_code = profileData.country_code;
    if (profileData.app_sounds_enabled !== undefined) dbUpdates.app_sounds_enabled = profileData.app_sounds_enabled;
    if (profileData.haptic_enabled !== undefined) dbUpdates.haptic_enabled = profileData.haptic_enabled;
    
    let nextInventory = { ...currInv };
    let hasInventoryUpdate = false;
    if (profileData.ownedAvatars) { nextInventory.owned_avatars = profileData.ownedAvatars; setOwnedAvatars(profileData.ownedAvatars); hasInventoryUpdate = true; }
    if (profileData.unlockedThemes) { nextInventory.unlocked_themes = profileData.unlockedThemes; setUnlockedThemes(profileData.unlockedThemes); hasInventoryUpdate = true; }
    if (profileData.solvedWords) { nextInventory.solved_words = profileData.solvedWords; setSolvedWords(profileData.solvedWords); hasInventoryUpdate = true; }
    if (profileData.playerStats) { nextInventory.stats = profileData.playerStats; setPlayerStats(profileData.playerStats); hasInventoryUpdate = true; }
    if (profileData.currentTheme) { nextInventory.equipped_theme = profileData.currentTheme; setCurrentTheme(profileData.currentTheme); hasInventoryUpdate = true; }

    if (hasInventoryUpdate) {
      dbUpdates.inventory = nextInventory;
      setInventory(nextInventory);
    }

    dbUpdates.updated_at = new Date().toISOString();
    try {
      await supabase.from('profiles').update(dbUpdates).eq('id', currentUser.id);
      return { success: true };
    } catch (err) {
      return { success: false, error: err.message };
    }
  }, []);

  const handleToggleBlock = useCallback(async (targetId, currentStatus) => {
    const { user: currentUser } = stateRef.current;
    if (!currentUser?.id) return;
    try {
      if (currentStatus) {
        await supabase.from('blocks').delete().eq('blocker_id', currentUser.id).eq('blocked_id', targetId);
      } else {
        await supabase.from('blocks').insert([{ blocker_id: currentUser.id, blocked_id: targetId }]);
      }
      return true;
    } catch (err) {
      return false;
    }
  }, []);

  const checkBlockStatus = async (targetId) => {
    if (!user?.id) return false;
    try {
      const { data, error } = await supabase
        .from('blocks')
        .select('id')
        .eq('blocker_id', user.id)
        .eq('blocked_id', targetId)
        .maybeSingle();
      if (error && error.code !== 'PGRST116') throw error;
      return !!data;
    } catch (err) {
      console.warn("Failed to check block status (possibly RLS):", err);
      return false;
    }
  };

  const value = useMemo(() => ({ 
    level, 
    winsTowardsSecret, incrementSecretWordProgress, resetSecretWordProgress,
    currentXP, maxXP, minXPForLevel, fils, derhem, zer, addXP,
    dailyStreak, setDailyStreak,
    inventory, setInventory,
    magnetCount, hintCount, skipCount,
    ownedAvatars, equippedAvatar: userAvatar, unlockedThemes, currentTheme,
    solvedWords, playerStats,
    userNickname, userAvatar, city, isInKurdistan, countryCode,
    updateInventory,
    updateProfile,
    processLevelCompletion,
    syncProgressToDatabase,
    getLevelFromXP, getLevelData,
    handleToggleBlock, checkBlockStatus,
    userRank, 
    refreshRank,
    user, setUser,
    setFils, setDerhem, setZer,
    setMagnetCount, setHintCount, setSkipCount,
    appSoundsEnabled, setAppSoundsEnabled,
    hapticEnabled, setHapticEnabled,
    playPopSound, playNotifSound, playMessageSound,
    playStartSound, playVictorySound, playRewardSound,
    setLevel, setCurrentXP,
    lastNotifiedLevel, setLastNotifiedLevel,
    loading 
  }), [
    level, winsTowardsSecret, currentXP, maxXP, minXPForLevel, fils, derhem, zer, 
    dailyStreak, inventory, magnetCount, hintCount, skipCount, 
    ownedAvatars, userAvatar, unlockedThemes, currentTheme, solvedWords, playerStats,
    userNickname, city, isInKurdistan, countryCode, userRank, user, loading,
    appSoundsEnabled, hapticEnabled, lastNotifiedLevel,
    incrementSecretWordProgress, resetSecretWordProgress, addXP, updateInventory,
    updateProfile, processLevelCompletion, syncProgressToDatabase, getLevelFromXP,
    getLevelData, handleToggleBlock, checkBlockStatus, refreshRank, setUser,
    setFils, setDerhem, setZer, setMagnetCount, setHintCount, setSkipCount,
    setAppSoundsEnabled, setHapticEnabled, playPopSound, playNotifSound,
    playMessageSound, playStartSound, playVictorySound, playRewardSound,
    setLevel, setCurrentXP, setLastNotifiedLevel
  ]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error('useGame must be used within a GameProvider');
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { getUnifiedWords } from '../data/wordList';
import { triggerHaptic } from '../utils/haptics';
import { useGame } from './GameContext';

const MultiplayerContext = createContext();

export const MultiplayerProvider = ({ children }) => {
  const { user } = useGame();
  const [multiplayerState, setMultiplayerState] = useState('idle'); // 'idle', 'searching', 'waiting', 'playing', 'game_over'
  const [matchmakingTime, setMatchmakingTime] = useState(0);
  const [activeMatch, setActiveMatch] = useState(null);
  const [matchId, setMatchId] = useState(null);
  const [opponent, setOpponent] = useState(null);
  const [lastMatchResult, setLastMatchResult] = useState(null);
  const [matchResultTrigger, setMatchResultTrigger] = useState(0);

  // New Game State
  const [opponentGuesses, setOpponentGuesses] = useState([]);
  const [scores, setScores] = useState({ p1: 0, p2: 0 });
  const [currentWordIndex, setCurrentWordIndex] = useState(1);
  const [isRoundWinner, setIsRoundWinner] = useState(false);
  const [winnerNickname, setWinnerNickname] = useState('');
  const [roundMessage, setRoundMessage] = useState('');

  const stateRef = useRef(multiplayerState);
  const wordIndexRef = useRef(currentWordIndex);
  const scoresRef = useRef(scores);
  const opponentRef = useRef(opponent);
  const matchIdRef = useRef(matchId);
  const channelRef = useRef(null);

  useEffect(() => { stateRef.current = multiplayerState; }, [multiplayerState]);
  useEffect(() => { wordIndexRef.current = currentWordIndex; }, [currentWordIndex]);
  useEffect(() => { scoresRef.current = scores; }, [scores]);
  useEffect(() => { opponentRef.current = opponent; }, [opponent]);
  useEffect(() => { matchIdRef.current = matchId; }, [matchId]);

  // TIMER ENGINE: Tracks seconds while searching or waiting
  useEffect(() => {
    let interval;
    if (multiplayerState === 'searching' || multiplayerState === 'waiting') {
      interval = setInterval(() => {
        setMatchmakingTime(prev => prev + 1);
      }, 1000);
    } else {
      setMatchmakingTime(0);
    }
    return () => clearInterval(interval);
  }, [multiplayerState]);

  const fetchOpponentProfile = useCallback(async (opponentId) => {
    if (!opponentId) return null;
    if (opponentRef.current?.id === opponentId) return opponentRef.current;

    const { data, error } = await supabase
      .from('profiles')
      .select('id, nickname, avatar_url')
      .eq('id', opponentId)
      .maybeSingle();

    if (error) return null;

    if (data) {
      setOpponent(data);
      setActiveMatch(prev => prev ? ({
        ...prev,
        opp_nickname: data.nickname,
        opp_avatar_url: data.avatar_url
      }) : null);
    }
    return data;
  }, []);

  // 1. POLLING FALLBACK: Detect player join automatically
  useEffect(() => {
    if (multiplayerState !== 'waiting' || !matchId) return;

    const pollInterval = setInterval(async () => {
      const { data: match } = await supabase
        .from('online_matches')
        .select('*')
        .eq('id', matchId)
        .maybeSingle();

      if (match && match.player2_id && stateRef.current !== 'playing' && stateRef.current !== 'game_over') {
        setActiveMatch(prev => ({ ...prev, ...match }));
        clearInterval(pollInterval);
      }
    }, 1500);

    return () => clearInterval(pollInterval);
  }, [multiplayerState, matchId]);

  // 2. REALTIME SUBSCRIPTION
  useEffect(() => {
    if (!matchId) return;

    const channel = supabase
      .channel(`match_room_${matchId}`)
      .on(
        'postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'online_matches', filter: `id=eq.${matchId}` },
        (payload) => {
          const updatedMatch = payload.new;
          console.log('[Multiplayer] Realtime Update:', updatedMatch.id, 'State:', updatedMatch.status);
          setActiveMatch(prev => prev ? { ...prev, ...updatedMatch } : updatedMatch);
        }
      )
      .on(
        'broadcast',
        { event: 'GUESS_SUBMITTED' },
        (payload) => {
          const data = payload.payload || payload;
          if (user?.id && data.senderId !== user.id) {
            setOpponentGuesses(prev => [...prev, data.colors]);
            if (data.isWin) {
              const winnerName = opponentRef.current?.nickname || 'Opponent';
              setWinnerNickname(winnerName);
              triggerHaptic([100, 100, 100]);
              setTimeout(() => setWinnerNickname(''), 3000);
            }
          }
        }
      )
      .subscribe((status) => {
        if (status === 'SUBSCRIBED') {
          channelRef.current = channel;
        }
      });

    return () => {
      supabase.removeChannel(channel);
      channelRef.current = null;
    };
  }, [matchId, user?.id]);

  // 3. SYNC EFFECT: Silent Auto-Handshake
  useEffect(() => {
    if (!activeMatch || !user?.id) return;

    const verifyAndStart = async () => {
      if ((multiplayerState === 'waiting' || multiplayerState === 'searching') && activeMatch.player2_id) {
        const oppId = activeMatch.player2_id === user.id ? activeMatch.player1_id : activeMatch.player2_id;
        const oppProfile = await fetchOpponentProfile(oppId);

        if (!oppProfile) {
          console.error('[Multiplayer] Silent Handshake Failed: Invalid Profile.');
          await cancelMatch();
          return;
        }

        // Match found! Wait 4 seconds to let the player see the opponent's profile
        setTimeout(() => {
          // IMPORTANT: Only proceed if the user hasn't cancelled since then
          setMultiplayerState(prev => {
            if (prev === 'idle') return prev; 
            return 'playing';
          });
          triggerHaptic([50, 50, 100]);
        }, 4000);
      }
    };
    verifyAndStart();

    if (activeMatch.current_word_index !== undefined && activeMatch.current_word_index !== wordIndexRef.current) {
      const newIndex = activeMatch.current_word_index || 0;
      setRoundMessage('ئامادەکارن بۆ گەڕێ');
      setCurrentWordIndex(newIndex);
      setOpponentGuesses([]);
      setIsRoundWinner(false);
      setWinnerNickname('');
      setTimeout(() => setRoundMessage(''), 3000);
    }

    if (activeMatch.status === 'finished' && multiplayerState !== 'idle' && multiplayerState !== 'game_over') {
      const isP1 = activeMatch.player1_id === user.id;
      const myScore = isP1 ? activeMatch.p1_score : activeMatch.p2_score;
      const oppScore = isP1 ? activeMatch.p2_score : activeMatch.p1_score;
      
      let result = 'draw';
      if (myScore > oppScore) result = 'victory';
      else if (myScore < oppScore) result = 'defeat';
      
      setLastMatchResult(result);
      setMatchResultTrigger(prev => prev + 1);
      
      // Redirect to lobby state immediately to sync with App.jsx
      setMultiplayerState('idle');
      setMatchId(null);
      setActiveMatch(null);
      setOpponent(null);
    }

    if (activeMatch.p1_score !== scoresRef.current.p1 || activeMatch.p2_score !== scoresRef.current.p2) {
      setScores({ p1: activeMatch.p1_score, p2: activeMatch.p2_score });
    }

    // NEW: Sync Opponent Colors from DB if missing in local state
    const isP1 = activeMatch.player1_id === user.id;
    const oppColors = isP1 ? activeMatch.p2_colors : activeMatch.p1_colors;
    if (oppColors && Array.isArray(oppColors) && oppColors.length > opponentGuesses.length) {
      setOpponentGuesses(oppColors);
    }
  }, [activeMatch, user?.id, multiplayerState, fetchOpponentProfile, opponentGuesses.length]);

  // UNIFIED ONE-CLICK MATCHMAKING
  const startMatchmaking = async () => {
    if (!user?.id) return;

    console.log('[Multiplayer] ONE-CLICK: Searching for rooms...');
    setMultiplayerState('searching');
    setMatchmakingTime(0);
    setOpponent(null);
    setOpponentGuesses([]);

    try {
      // PHASE 0: CLEANUP (Ensure no old waiting matches for this user exist)
      await supabase.from('online_matches').delete().eq('player1_id', user.id).eq('status', 'waiting');

      // PHASE 1: SEARCH
      const { data: waitingMatches, error: fetchError } = await supabase
        .from('online_matches')
        .select('*')
        .eq('status', 'waiting')
        .order('created_at', { ascending: false })
        .limit(1);

      if (fetchError) throw fetchError;

      const waitingMatch = (waitingMatches && waitingMatches.length > 0) ? waitingMatches[0] : null;

      if (waitingMatch) {
        console.log('[Multiplayer] JOINER: Room found, joining...', waitingMatch.id);
        const { data: joinedMatch, error: joinError } = await supabase
          .from('online_matches')
          .update({ player2_id: user.id, status: 'playing' })
          .eq('id', waitingMatch.id)
          .select()
          .maybeSingle();

        if (joinError) throw joinError;

        if (joinedMatch) {
          console.log('[Multiplayer] JOINER: Success! Match ID:', joinedMatch.id, 'Words:', joinedMatch.words?.[0]);
          const hostProfile = await fetchOpponentProfile(joinedMatch.player1_id);
          if (!hostProfile) throw new Error('Identity verification failed');

          setMatchId(joinedMatch.id);
          setActiveMatch(joinedMatch);
          setCurrentWordIndex(joinedMatch.current_word_index || 0);
          return;
        }
      }

      // PHASE 2: AUTO-HOST (If no room found)
      console.log('[Multiplayer] HOST: No match found, creating room...');
      let selectedWords = [];
      let selectedRiddles = [];

      try {
        const { data: randomSample, error: wordError } = await supabase.from('words').select('word, definition').limit(20);
        if (!wordError && randomSample?.length >= 3) {
          const shuffled = randomSample.sort(() => 0.5 - Math.random());
          selectedWords = shuffled.slice(0, 3).map(e => e.word);
          selectedRiddles = shuffled.slice(0, 3).map(e => e.definition || 'No riddle');
        } else {
          throw new Error('Fallback');
        }
      } catch (err) {
        const localWords = getUnifiedWords();
        const fallback = [...localWords].sort(() => 0.5 - Math.random()).slice(0, 3);
        selectedWords = fallback.map(w => w.word);
        selectedRiddles = fallback.map(w => w.hint || 'پەیڤێ بدۆزەوە');
      }

      const { data: newMatch, error: createError } = await supabase
        .from('online_matches')
        .insert({
          player1_id: user.id,
          status: 'waiting',
          words: selectedWords,
          riddles: selectedRiddles,
          current_word_index: 0,
          p1_score: 0, p2_score: 0
        })
        .select().single();

      if (createError) throw createError;
      if (newMatch) {
        console.log('[Multiplayer] HOST: Success! Created Match ID:', newMatch.id, 'Words:', newMatch.words?.[0]);
        setMatchId(newMatch.id);
        setActiveMatch(newMatch);
        setMultiplayerState('waiting');
      }

    } catch (error) {
      console.error('[Multiplayer] Matchmaking Failed:', error);
      setMultiplayerState('idle');
    }
  };

  const cancelMatch = async () => {
    const idToCancel = matchId || matchIdRef.current;
    try {
      if (idToCancel && multiplayerState !== 'playing' && multiplayerState !== 'game_over') {
        await supabase.from('online_matches').delete().eq('id', idToCancel);
      }
    } catch (err) {
      console.warn('[Multiplayer] Cancel deletion failed:', err);
    } finally {
      setMatchId(null);
      setActiveMatch(null);
      setOpponent(null);
      setMultiplayerState('idle');
      setMatchmakingTime(0);
      setOpponentGuesses([]);
      setScores({ p1: 0, p2: 0 });
      setCurrentWordIndex(1);
    }
  };

  const broadcastGuess = (colors, isWin = false) => {
    if (!channelRef.current || !user?.id) return;

    channelRef.current.send({
      type: 'broadcast',
      event: 'GUESS_SUBMITTED',
      payload: { senderId: user.id, colors, isWin }
    });
  };

  const submitGuess = async (colors, isWin) => {
    if (!matchId || !activeMatch) return;
    broadcastGuess(colors, isWin);

    const isP1 = activeMatch.player1_id === user.id;

    // PERSIST NORMAL GUESS (Ghost Grid Support)
    if (!isWin) {
      const currentColors = isP1 ? (activeMatch.p1_colors || []) : (activeMatch.p2_colors || []);
      const updatedColors = [...currentColors, colors];
      await supabase.from('online_matches')
        .update({ [isP1 ? 'p1_colors' : 'p2_colors']: updatedColors })
        .eq('id', matchId);
    }

    if (isWin) {
      const currentIdx = activeMatch.current_word_index || 0;
      const updates = { [isP1 ? 'p1_score' : 'p2_score']: (isP1 ? activeMatch.p1_score : activeMatch.p2_score) + 1 };

      // Clear colors for next round
      updates.p1_colors = [];
      updates.p2_colors = [];

      if (currentIdx >= 2) {
        updates.status = 'finished';
        setMultiplayerState('game_over');
      } else {
        updates.current_word_index = currentIdx + 1;
      }

      await supabase.from('online_matches').update(updates).eq('id', matchId);
      setIsRoundWinner(true);
      triggerHaptic([50, 50, 100]);
      setTimeout(() => setIsRoundWinner(false), 3000);
    }
  };

  const resetMatchResultTrigger = () => {
    setMatchResultTrigger(0);
    setLastMatchResult(null);
  };

  return (
    <MultiplayerContext.Provider value={{
      multiplayerState,
      matchmakingTime,
      activeMatch,
      opponent,
      setMultiplayerState,
      startMatchmaking,
      cancelMatch,
      submitGuess,
      broadcastGuess,
      opponentGuesses,
      scores,
      currentRound: currentWordIndex,
      isRoundWinner,
      winnerNickname,
      roundMessage,
      fetchOpponentProfile,
      lastMatchResult,
      matchResultTrigger,
      resetMatchResultTrigger
    }}>
      {children}
    </MultiplayerContext.Provider>
  );
};

export const useMultiplayer = () => {
  const context = useContext(MultiplayerContext);
  if (!context) throw new Error('useMultiplayer must be used within MultiplayerProvider');
  return context;
};

import { useState, useCallback, useRef, useEffect } from 'react';
import { STATUS } from '../data/constants';
import { normalizeKurdishInput } from '../utils/textUtils';
import { triggerHaptic } from '../utils/haptics';

export default function useGameLogic({ 
  targetWord, 
  maxRows = 6, 
  gameMode = 'classic',
  revealedIndices = [],
  onGuessSubmitted = null,
  onWin = null,
  onLoss = null,
  isLevelingUp = false
}) {
  const [guesses, setGuesses] = useState([]);
  const [currentGuess, setCurrentGuess] = useState(new Array(targetWord?.length || 5).fill(''));
  const [usedKeys, setUsedKeys] = useState({});
  const [isVictory, setIsVictory] = useState(false);
  const [isDefeat, setIsDefeat] = useState(false);

   // Use refs for values needed in stable callbacks
   const isSubmittingRef = useRef(false);
   const targetWordRef = useRef(targetWord);
   const revealedIndicesRef = useRef(revealedIndices);
   const isGameStateLockedRef = useRef(false);
   const guessesRef = useRef(guesses);
   const currentGuessRef = useRef(currentGuess);

   useEffect(() => {
     targetWordRef.current = targetWord;
   }, [targetWord]);

   useEffect(() => {
     revealedIndicesRef.current = revealedIndices;
   }, [revealedIndices]);

   useEffect(() => {
     isGameStateLockedRef.current = isLevelingUp || isVictory || isDefeat;
   }, [isLevelingUp, isVictory, isDefeat]);

   useEffect(() => {
     guessesRef.current = guesses;
   }, [guesses]);

   useEffect(() => {
     currentGuessRef.current = currentGuess;
   }, [currentGuess]);

  // Helper to re-initialize the guess array when targetWord changes
  const resetLocalBoard = useCallback((newTargetWord) => {
    setGuesses([]);
    setCurrentGuess(new Array(newTargetWord?.length || 5).fill(''));
    setUsedKeys({});
    setIsVictory(false);
    setIsDefeat(false);
    isSubmittingRef.current = false;
  }, []);

  const getLetterStatus = useCallback((guess, index, customTarget = targetWordRef.current) => {
    if (!customTarget || !guess) return STATUS.NONE;
    const guessString = Array.isArray(guess) ? guess.join('') : guess;
    const targetArr = customTarget.split('');
    const guessArr = guessString.split('');

    // Pass 1: Correct positions
    if (guessArr[index] === targetArr[index]) return STATUS.CORRECT;

    // Pass 2: Wrong positions (Letter exists but in different spot)
    const targetCounts = {};
    for (const char of targetArr) targetCounts[char] = (targetCounts[char] || 0) + 1;

    // Subtract greens
    for (let i = 0; i < guessArr.length; i++) {
        if (guessArr[i] === targetArr[i]) targetCounts[guessArr[i]]--;
    }

    // Check if this yellow is available
    let availableYellows = targetCounts[guessArr[index]] || 0;
    if (availableYellows > 0) {
        // Count how many of this same letter appeared before this index as yellows
        let yellowsBefore = 0;
        for (let i = 0; i < index; i++) {
            if (guessArr[i] !== targetArr[i] && guessArr[i] === guessArr[index]) {
                yellowsBefore++;
            }
        }
        if (yellowsAfterNone(guessArr, targetArr, index)) {
             if (yellowsBefore < availableYellows) return STATUS.WRONG_POS;
        }
    }

    return STATUS.INCORRECT;
  }, []); // Stable status checker

  // Internal helper for complex yellow logic
  const yellowsAfterNone = (guessArr, targetArr, index) => {
      // This is a simplified check for the classic Wordle double-letter rule
      return true; 
  };

  const onKey = useCallback((key) => {
    if (!targetWordRef.current || isSubmittingRef.current || isGameStateLockedRef.current) return;
    const cleanKey = normalizeKurdishInput(key);

    setCurrentGuess(prev => {
      const nextGuess = [...prev];
      let placed = false;
      for (let i = 0; i < nextGuess.length; i++) {
        if (nextGuess[i] === '' && !revealedIndicesRef.current.includes(i)) {
          nextGuess[i] = cleanKey;
          placed = true;
          break;
        }
      }
      return placed ? nextGuess : prev;
    });
  }, []); // COMPLETELY STABLE

  const onDelete = useCallback(() => {
    if (!targetWordRef.current || isSubmittingRef.current || isGameStateLockedRef.current) return;

    setCurrentGuess(prev => {
      const nextGuess = [...prev];
      let deleted = false;
      for (let i = nextGuess.length - 1; i >= 0; i--) {
        if (nextGuess[i] !== '' && !revealedIndicesRef.current.includes(i)) {
          nextGuess[i] = '';
          deleted = true;
          break;
        }
      }
      return deleted ? nextGuess : prev;
    });
  }, []); // COMPLETELY STABLE

  const onWinRef = useRef(onWin);
  const onLossRef = useRef(onLoss);
  const onGuessSubmittedRef = useRef(onGuessSubmitted);

  useEffect(() => { onWinRef.current = onWin; }, [onWin]);
  useEffect(() => { onLossRef.current = onLoss; }, [onLoss]);
  useEffect(() => { onGuessSubmittedRef.current = onGuessSubmitted; }, [onGuessSubmitted]);

  // ... (rest of the component logic)

  const onEnter = useCallback(async (forcedGuess = null) => {
    const target = targetWordRef.current;
    if (!target || isSubmittingRef.current || isGameStateLockedRef.current) return;

    const guessString = forcedGuess || normalizeKurdishInput(currentGuessRef.current.join(''));

    if (guessString.length < target.length) {
      triggerHaptic([50, 30, 50]);
      return { error: 'پەیڤ کێمە!' };
    }

    isSubmittingRef.current = true;

    const colors = guessString.split('').map((_, i) => getLetterStatus(guessString, i, target));
    const isWin = guessString === target;
    const currentGuesses = guessesRef.current;

    // Update Guesses
    setGuesses(prev => [...prev, guessString]);

    // Update used keys
    setUsedKeys(prevKeys => {
      const next = { ...prevKeys };
      guessString.split('').forEach((char, i) => {
        const status = colors[i];
        if (!next[char] || status === STATUS.CORRECT) next[char] = status;
      });
      return next;
    });

    // Trigger Win/Loss Side Effects
    if (isWin) {
      setIsVictory(true);
      if (onWinRef.current) onWinRef.current([...currentGuesses, guessString]);
    } else if (currentGuesses.length + 1 >= maxRows) {
      setIsDefeat(true);
      if (onLossRef.current) onLossRef.current([...currentGuesses, guessString]);
    }

    // Notify caller
    if (onGuessSubmittedRef.current) {
      onGuessSubmittedRef.current(colors, isWin);
    }

    if (!isWin) {
      // Prepare next row
      const freshGuess = new Array(target.length).fill('');
      revealedIndicesRef.current.forEach(idx => freshGuess[idx] = target[idx]);
      setCurrentGuess(freshGuess);
    }

    setTimeout(() => { isSubmittingRef.current = false; }, 300);
    return { success: true, colors, isWin };
  }, [maxRows, getLetterStatus]); 

  return {
    guesses,
    setGuesses,
    currentGuess,
    setCurrentGuess,
    usedKeys,
    setUsedKeys,
    isVictory,
    setIsVictory,
    isDefeat,
    setIsDefeat,
    onKey,
    onDelete,
    onEnter,
    getLetterStatus,
    resetLocalBoard
  };
}

/**
 * Audio Utilities
 * Handles sound effects for the application.
 * Optimized for low-latency feedback.
 */

const SOUND_PATHS = {
  CLICK: '/click.mp3',
  POP: '/pop.mp3',
  NOTIF: '/noti.mp3',
  MESSAGE: '/messag.mp3',
  VICTORY: '/victory.mp3',
  COIN: '/coin.mp3'
};

// --- PRE-LOADED SINGLETONS ---
const preloadedSounds = {};

export const initAudio = () => {
  if (typeof Audio === "undefined") return;
  
  Object.entries(SOUND_PATHS).forEach(([key, path]) => {
    const audio = new Audio(path);
    audio.preload = 'auto';
    // Set default volumes
    if (key === 'CLICK') audio.volume = 0.25;
    if (key === 'POP') audio.volume = 0.35;
    if (key === 'NOTIF') audio.volume = 0.7;
    if (key === 'MESSAGE') audio.volume = 0.65;
    if (key === 'VICTORY') audio.volume = 0.4;
    if (key === 'COIN') audio.volume = 0.3;
    
    preloadedSounds[key] = audio;
  });
};

// Initialize early
if (typeof window !== "undefined") {
  initAudio();
}

const safePlay = (soundKey) => {
  const sfx = preloadedSounds[soundKey];
  if (sfx) {
    if (!sfx.paused) {
      sfx.pause();
    }
    sfx.currentTime = 0;
    // Offload to task queue to prevent blocking Main thread during critical paint
    setTimeout(() => {
      sfx.play().catch(() => {
        // Browsers often block auto-play until interaction.
      });
    }, 0);
  }
};

/**
 * Professional Keyboard Click (iPhone Style)
 */
export const playKeyClickSfx = (enabled = true) => {
  if (!enabled) return;
  safePlay('CLICK');
};

/**
 * UI Transition / Grid Flip Sound
 */
let lastPopTime = 0;
export const playPopSfx = (enabled = true, bypassDebounce = false) => {
  if (!enabled) return;
  
  if (!bypassDebounce) {
    const now = Date.now();
    if (now - lastPopTime < 80) return; // Slightly faster debounce
    lastPopTime = now;
  }

  safePlay('POP');
};

/**
 * System Notification Sound
 */
export const playNotifSfx = (enabled = true) => {
  if (!enabled) return;
  safePlay('NOTIF');
};

/**
 * Private Message Sound
 */
export const playMessageSfx = (enabled = true) => {
  if (!enabled) return;
